// CRITIQUE: Initialiser window.translations IMM脙聣DIATEMENT avec un objet vide
// pour 脙漏viter toute erreur TDZ avant que les traductions compl脙篓tes ne soient charg脙漏es
// Cette initialisation doit 脙陋tre SYNCHRONE et IMM脙聣DIATE
// NE JAMAIS utiliser const/let/var translations car cela cr脙漏e une TDZ
(function() {
  if (typeof window !== 'undefined') {
    // S'assurer que window.translations existe AVANT toute utilisation
    if (!window.translations || typeof window.translations !== 'object') {
      window.translations = {};
    }
    SUPPORTED_LANGUAGES.forEach(lang => {
      if (!window.translations[lang] || typeof window.translations[lang] !== 'object') {
        window.translations[lang] = {};
      }
    });
  }
})();

// CRITIQUE: window.translations sera d脙漏fini juste apr脙篓s, mais on initialise window.t() d'abord
// pour 脙漏viter les erreurs de r脙漏f脙漏rence
// CRITIQUE: window.t() DOIT 脙陋tre d脙漏fini AVANT window.translations pour 脙漏viter les erreurs TDZ
// Mais window.t() doit utiliser window.translations, donc on initialise window.translations d'abord
// FONCTION window.t - VERSION S脙聣CURIS脙聣E SANS TDZ
window.t = function(k) {
  if (!k) return '';
  try {
    var w = window;
    if (!w || !w.translations) return k;
    var l = (typeof currentLanguage !== 'undefined' && currentLanguage) ? currentLanguage : 'fr';
    if (w.translations[l] && w.translations[l][k]) return w.translations[l][k];
    if (w.translations.fr && w.translations.fr[k]) return w.translations.fr[k];
    if (w.translations.en && w.translations.en[k]) return w.translations.en[k];
    return k;
  } catch(e) {
    return k;
  }
};

// D脙漏finir les fonctions critiques IMM脙聣DIATEMENT pour 脙漏viter les erreurs de r脙漏f脙漏rence
// Ces fonctions seront red脙漏finies plus tard avec leurs impl脙漏mentations compl脙篓tes
// Ouvre la discussion d'un 脙漏v脙漏nement (depuis la popup)
window.openEventDiscussion = function(type, id) {
  try {
    if (typeof currentUser === 'undefined' || !currentUser || !currentUser.isLoggedIn) {
      if (typeof window.openLoginModal === 'function') window.openLoginModal();
      else if (typeof openLoginModal === 'function') openLoginModal();
      return;
    }
    if (typeof window.openDiscussionModal === 'function') {
      window.openDiscussionModal(type, id);
    } else if (typeof openDiscussionModal === 'function') {
      openDiscussionModal(type, id);
    } else {
      setTimeout(() => {
        if (typeof window.openDiscussionModal === 'function') window.openDiscussionModal(type, id);
        else if (typeof openDiscussionModal === 'function') openDiscussionModal(type, id);
      }, 150);
    }
  } catch (e) {
    console.warn('openEventDiscussion error:', e);
  }
};

// Stub pour openGroupsModal - sera remplac脙漏 par l'impl脙漏mentation compl脙篓te plus tard
// CRITIQUE: Cette fonction DOIT 脙陋tre disponible imm脙漏diatement pour 脙漏viter les erreurs
window.openGroupsModal = function() {
  try {
    // V脙漏rifier si currentUser est disponible et si l'utilisateur est connect脙漏
    if (typeof currentUser !== 'undefined' && currentUser && currentUser.isLoggedIn) {
      // Si l'impl脙漏mentation compl脙篓te est d脙漏j脙聽 disponible (assign脙漏e plus tard), elle sera utilis脙漏e
      // Sinon, attendre un peu et r脙漏essayer
      setTimeout(() => {
        try {
          const currentImpl = window.openGroupsModal;
          // Si la fonction a 脙漏t脙漏 remplac脙漏e par l'impl脙漏mentation compl脙篓te (plus de 500 caract脙篓res)
          if (currentImpl && currentImpl.toString().length > 500) {
            currentImpl();
          } else if (typeof window.openLoginModal === 'function') {
            window.openLoginModal();
          } else if (typeof openLoginModal === 'function') {
            openLoginModal();
          }
        } catch (e) {
          console.warn('openGroupsModal error:', e);
        }
      }, 50);
    } else {
      // Utilisateur non connect脙漏 - ouvrir le modal de connexion
      if (typeof window.openLoginModal === 'function') {
        window.openLoginModal();
      } else if (typeof openLoginModal === 'function') {
        openLoginModal();
      } else {
        // Attendre que openLoginModal soit disponible
        setTimeout(() => {
          if (typeof window.openLoginModal === 'function') {
            window.openLoginModal();
          } else if (typeof openLoginModal === 'function') {
            openLoginModal();
          }
        }, 100);
      }
    }
  } catch (e) {
    console.warn('openGroupsModal stub error:', e);
  }
};

// Stub pour sharePopup - sera remplac脙漏 par l'impl脙漏mentation compl脙篓te plus tard
window.sharePopup = function(type, id) {
  try {
    if (!type || !id) {
      console.warn('sharePopup: type and id are required');
      return;
    }
    
    // V脙漏rifier si shareItem est disponible
    if (typeof shareItem === 'function') {
      shareItem(type, id);
    } else if (typeof window.shareItem === 'function') {
      window.shareItem(type, id);
    } else {
      // Attendre que shareItem soit disponible
      setTimeout(() => {
        try {
          if (typeof shareItem === 'function') {
            shareItem(type, id);
          } else if (typeof window.shareItem === 'function') {
            window.shareItem(type, id);
          } else {
            console.warn('sharePopup: shareItem not available yet');
          }
        } catch (e) {
          console.warn('sharePopup timeout error:', e);
        }
      }, 100);
    }
  } catch (e) {
    console.warn('sharePopup stub error:', e);
  }
};

