// 芒職聽茂赂聫芒職聽茂赂聫芒職聽茂赂聫 VRAI PAIEMENT STRIPE CHECKOUT
async function processStripePayment(amount) {
  const submitBtn = document.getElementById("stripe-submit-btn");
  if (submitBtn) {
    submitBtn.disabled = true;
    submitBtn.innerHTML = '芒聫鲁 Redirection vers Stripe...';
  }
  
  try {
    const data = window.pendingPublishData;
    if (!data) {
      throw new Error('Donn脙漏es de publication manquantes');
    }
    
    // G脙漏n脙漏rer un userId si l'utilisateur n'en a pas
    const userId = currentUser?.id || currentUser?.email || `guest_${Date.now()}`;
    
    console.log('[STRIPE] Cr脙漏ation session Checkout pour', amount, 'CHF, userId:', userId);
    
    // Appeler le backend pour cr脙漏er une session Stripe Checkout
    // 芒職聽茂赂聫 Champs requis par le backend: userId, paymentType, amount
    const response = await fetch(`${window.API_BASE_URL}/payments/create-checkout-session`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': localStorage.getItem('id_token') ? `Bearer ${localStorage.getItem('id_token')}` : ''
      },
      body: JSON.stringify({
        userId: userId,
        paymentType: 'publication',
        amount: amount * 100, // Convertir en centimes pour Stripe
        currency: 'chf',
        email: currentUser?.email || data.newItem?.email || '',
        product_name: `Publication ${data.mode}: ${data.newItem?.title || '脙聣v脙漏nement'}`,
        description: `Boost: ${data.boost}${data.newItem?.repeat?.enabled ? ' + R脙漏p脙漏tition' : ''}`,
        metadata: {
          eventId: String(data.newItem?.id || ''),
          mode: data.mode || 'event',
          boost: data.boost || 'standard',
          repeatEnabled: String(data.newItem?.repeat?.enabled || false),
          title: data.newItem?.title || ''
        }
      })
    });
    
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || `Erreur serveur: ${response.status}`);
    }
    
    const result = await response.json();
    
    if (!result.sessionId && !result.url) {
      throw new Error('Session Stripe non cr脙漏脙漏e');
    }
    
    // Sauvegarder les donn脙漏es en localStorage pour apr脙篓s le paiement
    localStorage.setItem('pendingPublishData', JSON.stringify(data));
    
    // Rediriger vers Stripe Checkout
    if (result.url) {
      // Redirection directe vers l'URL de checkout
      window.location.href = result.url;
    } else if (result.sessionId) {
      // Charger Stripe.js si pas encore charg脙漏
      if (typeof Stripe === 'undefined' && typeof window.loadStripe === 'function') {
        await window.loadStripe();
      }
      // Utiliser Stripe.js pour rediriger
      if (typeof Stripe !== 'undefined') {
        const stripeInstance = Stripe(result.publicKey || 'pk_live_51Sfg8g2YO5zMBO7yRz2yRw9SZMJhYY8bfxLYT7v6VgQ77lFFwaUOGa5WYD1h7SDUgNkyABKnGFu3KN5p4PwT1Eqr00CisIZv67');
        const { error } = await stripeInstance.redirectToCheckout({ sessionId: result.sessionId });
        if (error) {
          throw new Error(error.message);
        }
      } else {
        throw new Error('Stripe.js non charg脙漏');
      }
    }
    
  } catch (error) {
    console.error('[STRIPE] Erreur:', error);
    showNotification(`芒聺聦 Erreur: ${error.message}`, "error");
    
    if (submitBtn) {
      submitBtn.disabled = false;
      submitBtn.innerHTML = `冒聼聮鲁 Payer ${amount}.- CHF`;
    }
  }
}

// Finaliser la publication apr脙篓s paiement
async function finalizePublish() {
  if (window._publishFinalized) {
    console.log('[PUBLISH] 芒聫颅茂赂聫 Publication d脙漏j脙聽 finalis脙漏e, ignor脙漏');
    return;
  }

  const data = window.pendingPublishData;
  if (!data) {
    console.error('[PUBLISH] 芒聺聦 Donn脙漏es de publication perdues - pendingPublishData est null');
    showNotification("芒聺聦 Erreur: Donn脙漏es de publication perdues. Veuillez r脙漏essayer.", "error");
    return;
  }
  
  window._publishFinalized = true;
  console.log('[PUBLISH] 冒聼聰聞 Tentative de cr脙漏ation avec donn脙漏es:', JSON.stringify(data.newItem, null, 2));
  
  // Sauvegarder dans le backend D'ABORD
  let backendSuccess = false;
  try {
    const token = typeof getAuthToken === 'function' ? getAuthToken() : localStorage.getItem('accessToken');
    const headers = { 'Content-Type': 'application/json' };
    if (token) headers['Authorization'] = 'Bearer ' + token;
    
    // Pr脙漏parer les donn脙漏es avec les bons noms de champs pour le backend
    const backendData = {
      ...data.newItem,
      // Mapper les champs frontend -> backend
      location: data.newItem.address || data.newItem.location,
      latitude: data.newItem.lat || data.newItem.latitude,
      longitude: data.newItem.lng || data.newItem.longitude,
      userId: currentUser?.id,
      creator_id: currentUser?.id,
      paymentStatus: 'paid',
      paymentAmount: data.price
    };
    
    console.log('[PUBLISH] 冒聼聯陇 Envoi au backend:', window.API_BASE_URL + '/' + data.mode + 's');
    console.log('[PUBLISH] 冒聼聯陇 Donn脙漏es envoy脙漏es:', JSON.stringify(backendData, null, 2));
    
    const response = await fetch(`${window.API_BASE_URL}/${data.mode}s`, {
      method: 'POST',
      headers: headers,
      body: JSON.stringify(backendData)
    });
    
    const responseText = await response.text();
    console.log('[PUBLISH] 冒聼聯楼 R脙漏ponse backend:', response.status, responseText);
    
    if (response.ok) {
      backendSuccess = true;
      // R脙漏cup脙漏rer l'ID g脙漏n脙漏r脙漏 par le backend
      try {
        const result = JSON.parse(responseText);
        if (result.id) {
          console.log('[PUBLISH] 芒聹聟 ID backend re脙搂u:', result.id);
          data.newItem.id = result.id; // Utiliser l'ID du backend !
        }
        if (result.creator_id) {
          console.log('[PUBLISH] 芒聹聟 creator_id confirm脙漏:', result.creator_id);
        }
        // R脙漏cup脙漏rer l'URL de l'image upload脙漏e vers S3
        if (result.image_url) {
          data.newItem.image_url = result.image_url;
          data.newItem.imageUrl = result.image_url;
          console.log('[PUBLISH] 芒聹聟 Image URL S3 re脙搂ue:', result.image_url.substring(0, 80) + '...');
        }
      } catch (e) {
        console.warn('[PUBLISH] Impossible de parser la r脙漏ponse:', e);
      }
      console.log('[PUBLISH] 芒聹聟 脙聣v脙漏nement cr脙漏脙漏 avec succ脙篓s dans le backend');
    } else {
      console.error('[PUBLISH] 芒聺聦 Erreur backend:', response.status, responseText);
      showNotification(`芒聺聦 Erreur serveur (${response.status}): ${responseText}`, "error");
    }
  } catch (error) {
    console.error('[PUBLISH] 芒聺聦 Erreur r脙漏seau:', error);
    showNotification("芒聺聦 Erreur r脙漏seau lors de la publication. V脙漏rifiez votre connexion.", "error");
  }
  
  // Ajouter aux donn脙漏es locales SEULEMENT si backend OK
  if (backendSuccess) {
    const itemId = data.newItem.id;
    if (data.mode === "event") {
      if (!eventsData.some(e => e.id === itemId)) {
        eventsData.push(data.newItem);
      }
      if (typeof loadedEventIds !== 'undefined') loadedEventIds.add(itemId);
    } else if (data.mode === "booking") {
      bookingsData.push(data.newItem);
    } else if (data.mode === "service") {
      servicesData.push(data.newItem);
    }
    
    // Fermer le modal et rafra脙庐chir
    closePublishModal();
    refreshMarkers();
    refreshListView();
    
    // Centrer la carte sur le nouveau point
    if (map && data.lat && data.lng) {
      map.setView([data.lat, data.lng], 14);
    }
    
    // Message de succ脙篓s
    showNotification(`芒聹聟 Paiement re脙搂u ! ${data.mode === 'event' ? '脙聣v脙漏nement' : data.mode === 'booking' ? 'Booking' : 'Service'} publi脙漏 avec succ脙篓s !`, "success");
  }
  
  window.pendingPublishData = null;
  setTimeout(() => { window._publishFinalized = false; }, 5000);
}

