function generateRandomDate(daysFromNow, hoursVariation = 0) {
  const date = new Date();
  date.setDate(date.getDate() + daysFromNow);
  date.setHours(20 + Math.floor(Math.random() * 4) + hoursVariation);
  date.setMinutes(Math.random() > 0.5 ? 0 : 30);
  return date.toISOString().slice(0, 16);
}

// Extrait toutes les sous-cat脙漏gories les plus profondes d'un arbre
function extractDeepestCategories(tree, result = [], visited = new WeakSet(), depth = 0) {
  // Protection contre r脙漏cursion infinie
  if (depth > 50) {
    console.warn('芒職聽茂赂聫 extractDeepestCategories: profondeur maximale atteinte');
    return result;
  }
  
  if (!tree) return result;
  
  // Protection contre r脙漏f脙漏rences circulaires
  if (typeof tree === 'object' && tree !== null) {
    if (visited.has(tree)) {
      return result; // D脙漏j脙聽 visit脙漏, 脙漏viter la boucle
    }
    visited.add(tree);
  }
  
  if (Array.isArray(tree)) {
    // C'est une liste de feuilles - les plus profondes !
    tree.forEach(item => {
      const name = typeof item === 'string' ? item : (item && item.name ? item.name : '');
      if (name && !result.includes(name)) {
        result.push(name);
      }
    });
    return result;
  }
  
  // Parcourir r脙漏cursivement seulement si c'est un objet
  if (typeof tree === 'object' && tree !== null) {
    for (const key in tree) {
      if (tree.hasOwnProperty(key)) {
        extractDeepestCategories(tree[key], result, visited, depth + 1);
      }
    }
  }
  
  return result;
}

