// Appeler le calcul des rangs Platinum apr脙篓s la g脙漏n脙漏ration des donn脙漏es
function finalizeDataGeneration() {
  // Assigner des rangs Platinum al脙漏atoires aux 脙漏v脙漏nements platinum (pour la d脙漏mo)
  eventsData.forEach(ev => {
    if (ev.boost === "platinum" && !ev.platinumBid) {
      // Ench脙篓re al脙漏atoire entre 15 et 50 pour la d脙漏mo
      ev.platinumBid = 15 + Math.floor(Math.random() * 36);
    }
  });
  
  // Calculer les rangs par r脙漏gion
  calculatePlatinumRanks();
}

