window.updateBackendData = function (mode, data) {
  if (!Array.isArray(data)) data = [];
  if (mode === "event") eventsData = data;
  if (mode === "booking") bookingsData = data;
  if (mode === "service") servicesData = data;

  ensureDemoPoints();
  finalizeDataGeneration();
  filteredData = null;
  refreshMarkers();
  refreshListView();
};

