// Itin脙漏raire direct
function openRoute(type, id) {
  const item = getItemById(type, id);
  if (!item) return;
  
  const address = item.address || `${item.lat},${item.lng}`;
  const encodedAddress = encodeURIComponent(address);
  
  // Ouvrir Google Maps avec l'itin脙漏raire
  const url = `https://www.google.com/maps/dir/?api=1&destination=${encodedAddress}`;
  window.open(url, '_blank');
  
  showNotification("冒聼聴潞茂赂聫 Itin脙漏raire ouvert dans Google Maps", "success");
}

// Partager
function shareItem(type, id) {
  // R脙漏cup脙漏rer les infos de l'item
  // Cette fonction fonctionne pour TOUS les types d'脙漏v脙漏nements :
  // - 脙聣v脙漏nements de test
  // - 脙聣v脙漏nements r脙漏els
  // - 脙聣v脙漏nements g脙漏n脙漏r脙漏s par IA
  // - Bookings
  // - Services
  let item = null;
  let title = "D脙漏couvrez cet 脙漏v脙漏nement sur MapEvent !";
  
  if (type === "event") {
    item = eventsData.find(e => e.id === id);
    if (item) {
      // Utiliser le titre de l'脙漏v脙漏nement (fonctionne pour test, r脙漏el, AI)
      title = item.title || item.name || title;
    }
  } else if (type === "booking") {
    item = bookingsData.find(b => b.id === id);
    if (item) title = item.title || item.name || title;
  } else if (type === "service") {
    item = servicesData.find(s => s.id === id);
    if (item) title = item.title || item.name || title;
  }
  
  // Mettre 脙聽 jour les m脙漏tadonn脙漏es Open Graph pour le partage
  // Ces m脙漏tadonn脙漏es seront utilis脙漏es par Facebook, Twitter, LinkedIn, etc.
  if (item) {
    updateOpenGraphMetadata(type, id, item);
    console.log(`芒聹聟 Partage de ${type} ${id}: "${title}"`);
  } else {
    console.warn(`芒職聽茂赂聫 ${type} ${id} non trouv脙漏 pour le partage`);
  }
  
  shareItemModal(type, id, item, title);
}

// Mettre 脙聽 jour les m脙漏tadonn脙漏es Open Graph pour le partage social
function updateOpenGraphMetadata(type, id, item) {
  const baseUrl = window.location.origin + window.location.pathname;
  const shareUrl = `${baseUrl}?${type}=${id}`;
  
  // Obtenir l'image de l'脙漏v脙漏nement
  const imageCandidates = getImageCandidatesForItem(item);
  let imageUrl = imageCandidates[0] || OVERLAY_IMAGES.DEFAULT;
  
  // S'assurer que l'URL de l'image est absolue et compl脙篓te
  if (!imageUrl.startsWith('http')) {
    // Si l'URL est relative, la rendre absolue
    if (imageUrl.startsWith('/')) {
      imageUrl = window.location.origin + imageUrl;
    } else {
      imageUrl = window.location.origin + '/' + imageUrl;
    }
  }
  
  // Obtenir la description optimis脙漏e pour les r脙漏seaux sociaux
  let description = '';
  if (item.description) {
    description = item.description.length > 200 
      ? item.description.substring(0, 197) + '...' 
      : item.description;
  } else {
    const dateStr = item.startDate 
      ? new Date(item.startDate).toLocaleDateString('fr-FR', { 
          weekday: 'long', 
          day: 'numeric', 
          month: 'long',
          year: 'numeric'
        })
      : '';
    const locationStr = item.city || item.address || 'Suisse';
    description = `${dateStr ? dateStr + ' - ' : ''}${locationStr} | D脙漏couvrez cet 脙漏v脙漏nement sur MapEvent`;
  }
  
  // Cr脙漏er un titre optimis脙漏 avec le titre de l'脙漏v脙漏nement en premier
  // Fonctionne pour TOUS les types d'脙漏v脙漏nements : test, r脙漏el, AI, etc.
  const eventTitle = item.title || item.name || '脙聣v脙漏nement';
  // Le titre doit 脙陋tre le titre de l'脙漏v脙漏nement uniquement (sans suffixe)
  // Cela fonctionne pour les 脙漏v脙漏nements de test ET les vrais 脙漏v脙漏nements
  const title = eventTitle.trim(); // Titre principal = titre de l'脙漏v脙漏nement uniquement
  
  // Description enrichie avec date et lieu pour plus de contexte
  let enrichedDescription = description;
  if (item.startDate) {
    const dateStr = new Date(item.startDate).toLocaleDateString('fr-FR', { 
      weekday: 'long', 
      day: 'numeric', 
      month: 'long',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
    const locationStr = item.city || item.address || '';
    if (locationStr) {
      enrichedDescription = `${dateStr} - ${locationStr}${description ? ' | ' + description : ''}`;
    } else {
      enrichedDescription = `${dateStr}${description ? ' | ' + description : ''}`;
    }
  }
  
  // Mettre 脙聽 jour les m脙漏tadonn脙漏es Open Graph (Facebook, LinkedIn, etc.)
  // IMPORTANT: Ces m脙漏tadonn脙漏es fonctionnent pour TOUS les types d'脙漏v脙漏nements
  // (test, r脙漏el, AI, etc.) car elles utilisent les propri脙漏t脙漏s standard (title, description, etc.)
  updateMetaTag('og:url', shareUrl);
  updateMetaTag('og:title', title);
  updateMetaTag('og:description', enrichedDescription);
  updateMetaTag('og:image', imageUrl);
  updateMetaTag('og:image:width', '1200');
  updateMetaTag('og:image:height', '630');
  updateMetaTag('og:image:type', 'image/jpeg');
  updateMetaTag('og:type', 'website');
  updateMetaTag('og:site_name', 'MapEvent');
  updateMetaTag('og:locale', 'fr_FR');
  
  // Log pour debug (peut 脙陋tre retir脙漏 en production)
  console.log(`冒聼聯卤 M脙漏tadonn脙漏es Open Graph mises 脙聽 jour:`, {
    title: title,
    description: enrichedDescription.substring(0, 50) + '...',
    image: imageUrl.substring(0, 50) + '...',
    url: shareUrl
  });
  
  // Mettre 脙聽 jour les m脙漏tadonn脙漏es Twitter Card
  updateMetaTag('twitter:url', shareUrl);
  updateMetaTag('twitter:title', title);
  updateMetaTag('twitter:description', enrichedDescription);
  updateMetaTag('twitter:image', imageUrl);
  updateMetaTag('twitter:card', 'summary_large_image');
  updateMetaTag('twitter:site', '@mapevent');
  
  // Mettre 脙聽 jour la meta description standard
  updateMetaTag('description', enrichedDescription, 'name');
  
  // Mettre 脙聽 jour le titre de la page avec le titre de l'脙漏v脙漏nement
  document.title = title;
  
  // Ajouter aussi un meta title pour certains r脙漏seaux sociaux
  updateMetaTag('title', title, 'name');
  
  // Ajouter un lien canonique pour 脙漏viter les doublons
  let canonical = document.querySelector('link[rel="canonical"]');
  if (!canonical) {
    canonical = document.createElement('link');
    canonical.setAttribute('rel', 'canonical');
    document.head.appendChild(canonical);
  }
  canonical.setAttribute('href', shareUrl);
}

// Fonction utilitaire pour mettre 脙聽 jour les m脙漏tadonn脙漏es
function updateMetaTag(property, content, attribute = 'property') {
  let meta = document.querySelector(`meta[${attribute}="${property}"]`);
  if (!meta) {
    meta = document.createElement('meta');
    meta.setAttribute(attribute, property);
    document.head.appendChild(meta);
  }
  meta.setAttribute('content', content);
}

// V脙漏rifier les param脙篓tres URL et mettre 脙聽 jour les m脙漏tadonn脙漏es Open Graph
function checkUrlParamsAndUpdateMetadata() {
  const urlParams = new URLSearchParams(window.location.search);
  const eventId = urlParams.get('event');
  const bookingId = urlParams.get('booking');
  const serviceId = urlParams.get('service');
  
  // Fonction pour essayer de mettre 脙聽 jour les m脙漏tadonn脙漏es
  function tryUpdateMetadata(maxAttempts = 15) {
    let attempts = 0;
    const checkInterval = setInterval(() => {
      attempts++;
      let item = null;
      let type = null;
      let id = null;
      
      if (eventId && eventsData && eventsData.length > 0) {
        item = eventsData.find(e => e.id === parseInt(eventId));
        type = 'event';
        id = parseInt(eventId);
      } else if (bookingId && bookingsData && bookingsData.length > 0) {
        item = bookingsData.find(b => b.id === parseInt(bookingId));
        type = 'booking';
        id = parseInt(bookingId);
      } else if (serviceId && servicesData && servicesData.length > 0) {
        item = servicesData.find(s => s.id === parseInt(serviceId));
        type = 'service';
        id = parseInt(serviceId);
      }
      
      if (item && type && id) {
        clearInterval(checkInterval);
        console.log(`芒聹聟 Mise 脙聽 jour des m脙漏tadonn脙漏es Open Graph pour ${type} ${id}`);
        updateOpenGraphMetadata(type, id, item);
      } else if (attempts >= maxAttempts) {
        clearInterval(checkInterval);
        console.warn(`芒職聽茂赂聫 Impossible de mettre 脙聽 jour les m脙漏tadonn脙漏es apr脙篓s ${maxAttempts} tentatives`);
      }
    }, 300); // V脙漏rifier toutes les 300ms
  }
  
  // Commencer imm脙漏diatement
  tryUpdateMetadata();
}

window.checkUrlParamsAndUpdateMetadata = checkUrlParamsAndUpdateMetadata;
window.updateOpenGraphMetadata = updateOpenGraphMetadata;
window.updateMetaTag = updateMetaTag;

