// 芒職聽茂赂聫芒職聽茂赂聫芒職聽茂赂聫 WRAPPER SIMPLIFI脙聣 : D脙漏l脙篓gue directement 脙聽 window.openLoginModal de auth.js
// 芒職聽茂赂聫芒職聽茂赂聫芒職聽茂赂聫 CRITIQUE : Ne JAMAIS 脙漏craser window.openLoginModal ici !
function openLoginModal() {
  // 芒職聽茂赂聫芒職聽茂赂聫芒職聽茂赂聫 SIMPLE : Appeler directement window.openLoginModal de auth.js
  if (typeof window.openLoginModal === 'function') {
    const authFn = window.openLoginModal;
    const fnSource = authFn.toString();
    // 芒職聽茂赂聫芒職聽茂赂聫芒職聽茂赂聫 V脙聣RIFICATION : Si ce n'est pas le wrapper lui-m脙陋me, l'appeler
    if (!fnSource.includes('openLoginModalCalling')) {
      return authFn();
    }
  }
  
  // Si auth.js n'est pas encore charg脙漏, attendre un peu
  setTimeout(() => {
    if (typeof window.openLoginModal === 'function') {
      const authFn = window.openLoginModal;
      const fnSource = authFn.toString();
      if (!fnSource.includes('openLoginModalCalling')) {
        return authFn();
      }
    }
    // Fallback vers openAuthModal si n脙漏cessaire
    if (typeof window.openAuthModal === 'function') {
      return window.openAuthModal('login');
    }
  }, 100);
}

// 芒職聽茂赂聫芒職聽茂赂聫芒職聽茂赂聫 CRITIQUE : NE JAMAIS faire window.openLoginModal = openLoginModal ici !
// Cela cr脙漏erait une r脙漏cursion infinie car le wrapper s'appellerait lui-m脙陋me
// 芒職聽茂赂聫芒職聽茂赂聫芒職聽茂赂聫 SUPPRIM脙聣 : window.openLoginModal = openLoginModal; (ligne supprim脙漏e pour 脙漏viter la r脙漏cursion)

function openRegisterModal() {
  console.log('[AUTH] openRegisterModal (wrapper) called');
  if (typeof window.openAuthModal === 'function') {
    return window.openAuthModal('register');
  } else if (typeof window.openRegisterModal === 'function') {
    // Fallback : utiliser directement window.openRegisterModal si disponible
    return window.openRegisterModal();
  } else {
    console.error('[AUTH] ERREUR: window.openAuthModal non disponible (auth.js non charg脙漏 ?)');
  }
}

