      photoInput.addEventListener('input', photoChangeHandler, true); // Aussi sur 'input' au cas o脙鹿
      console.log('[PRO REGISTER] 芒聹聟芒聹聟芒聹聟芒聹聟芒聹聟 Event listeners change ET input attach脙漏s a pro-photo-input avec useCapture=true');
      
