// Gestion de l'upload de photo de profil
function handleProPhotoUpload(event) {
  // 芒職聽茂赂聫芒職聽茂赂聫芒職聽茂赂聫 CRITIQUE : Emp脙陋cher TOUTE propagation pour 脙漏viter la fermeture du formulaire
  if (event) {
    event.preventDefault();
    event.stopPropagation();
    event.stopImmediatePropagation();
    if (event.cancelBubble !== undefined) {
      event.cancelBubble = true;
    }
  }
  console.log('[PHOTO] 冒聼聰楼冒聼聰楼冒聼聰楼 handleProPhotoUpload APPEL脙聣E!', event);
  const file = event.target.files[0];
  if (!file) {
    console.log('[PHOTO] Aucun fichier s脙漏lectionn脙漏');
    return;
  }

  console.log('[PHOTO] 冒聼聯聛 Fichier d脙漏tect脙漏:', { name: file.name, size: file.size, type: file.type });

  // V脙漏rifier la taille (max 5MB)
  if (file.size > 5 * 1024 * 1024) {
    showError('pro-photo-error', 'La photo est trop grande (max 5MB)');
    console.error('[PHOTO] Fichier trop grand:', file.size);
    return;
  }

  // V脙漏rifier le type
  if (!file.type.startsWith('image/')) {
    showError('pro-photo-error', 'Veuillez s脙漏lectionner une image');
    console.error('[PHOTO] Type de fichier invalide:', file.type);
    return;
  }

  console.log('[PHOTO] 芒聹聟 Fichier valide, d脙漏but conversion en base64...');

  // Lire et convertir en Base64
  const reader = new FileReader();
  reader.onload = function(e) {
    const base64 = e.target.result;
    console.log('[PHOTO] 芒聹聟 Photo convertie en base64, longueur:', base64.length);
    
    // S'assurer que registerData existe
    if (!window.registerData) {
      window.registerData = {};
      console.log('[PHOTO] 芒職聽茂赂聫 registerData cr脙漏脙漏 car n\'existait pas');
    }
    
    // Sauvegarder dans registerData.profilePhoto ET registerData.photoData
    window.registerData.profilePhoto = base64;
    window.registerData.photoData = base64; // AUSSI dans photoData pour compatibilit脙漏
    
    console.log('[PHOTO] 芒聹聟芒聹聟芒聹聟 Photo sauvegard脙漏e dans registerData.profilePhoto ET registerData.photoData');
    console.log('[PHOTO] registerData.profilePhoto existe:', !!window.registerData.profilePhoto);
    console.log('[PHOTO] registerData.photoData existe:', !!window.registerData.photoData);
    console.log('[PHOTO] registerData.photoData longueur:', window.registerData.photoData ? window.registerData.photoData.length : 0);
    console.log('[PHOTO] registerData.photoData d脙漏but:', window.registerData.photoData ? (window.registerData.photoData.substring(0, 50) + '...') : 'null');
    
    // Afficher la preview
    const preview = document.getElementById('pro-photo-preview');
    const placeholder = document.getElementById('pro-photo-placeholder');
    const photoText = document.querySelector('.pro-register-photo-text');
    
    if (preview) {
      preview.src = base64;
      preview.style.display = 'block';
      preview.classList.add('show');
      console.log('[PHOTO] 芒聹聟 Preview mise 脙聽 jour avec base64');
    } else {
      console.warn('[PHOTO] 芒職聽茂赂聫 Preview non trouv脙漏e');
    }
    if (placeholder) {
      placeholder.style.display = 'none';
    }
    if (photoText) {
      photoText.textContent = 'Cliquez pour changer la photo';
    }
    
    // Cacher l'erreur
    showError('pro-photo-error', '');
    
    // V脙漏rification finale
    setTimeout(() => {
      console.log('[PHOTO] 冒聼聰聧 V脙聣RIFICATION FINALE apr脙篓s 100ms:');
      console.log('[PHOTO] registerData existe:', !!window.registerData);
      console.log('[PHOTO] registerData.photoData:', window.registerData?.photoData ? 'PR脙聣SENT (' + window.registerData.photoData.length + ' chars)' : 'NULL');
      console.log('[PHOTO] registerData.profilePhoto:', window.registerData?.profilePhoto ? 'PR脙聣SENT (' + window.registerData.profilePhoto.length + ' chars)' : 'NULL');
    }, 100);
  };
  
  reader.onerror = function(error) {
    console.error('[PHOTO] 芒聺聦 Erreur lors de la lecture du fichier:', error);
    showError('pro-photo-error', 'Erreur lors de la lecture de la photo');
  };
  
  reader.readAsDataURL(file);
  console.log('[PHOTO] 冒聼聯聳 FileReader.readAsDataURL() appel脙漏');
}

