// Validation des champs
async function validateProField(fieldName, value) {
  const errorEl = document.getElementById(`pro-${fieldName}-error`);
  const successEl = document.getElementById(`pro-${fieldName}-success`);
  const inputEl = document.getElementById(`pro-${fieldName}`);
  
  if (!errorEl || !inputEl) return true;

  // R脙漏initialiser les 脙漏tats visuels
  inputEl.classList.remove('field-error', 'field-success');
  inputEl.style.borderColor = '';
  inputEl.style.boxShadow = '';
  showError(`pro-${fieldName}-error`, '');
  showSuccess(`pro-${fieldName}-success`, '');

  let isValid = true;
  let errorMsg = '';
  let successMsg = '';

  switch(fieldName) {
    case 'firstname':
    case 'lastname':
      if (!value || value.trim().length < 2) {
        isValid = false;
        errorMsg = '芒職聽茂赂聫 Minimum 2 caract脙篓res requis';
      } else if (value.length > 50) {
        isValid = false;
        errorMsg = '芒職聽茂赂聫 Maximum 50 caract脙篓res';
      } else if (!/^[a-zA-Z脙聽脙隆脙垄脙陇脙拢脙楼脙篓脙漏脙陋脙芦脙卢脙颅脙庐脙炉脙虏脙鲁脙麓脙露脙碌脙鹿脙潞脙禄脙录脙陆脙驴脙卤脙搂脙聙脙聛脙聜脙聞脙聝脙聟脙聢脙聣脙聤脙聥脙聦脙聧脙聨脙聫脙聮脙聯脙聰脙聳脙聲脙聶脙職脙聸脙聹脙聺脜赂脙聭脙聡\s-]+$/.test(value)) {
        isValid = false;
        errorMsg = '芒職聽茂赂聫 Seules les lettres sont autoris脙漏es';
      } else {
        successMsg = '芒聹聯 Format valide';
      }
      break;
    
    case 'email':
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!value) {
        isValid = false;
        errorMsg = '芒職聽茂赂聫 Email requis';
      } else if (!emailRegex.test(value)) {
        isValid = false;
        errorMsg = '芒職聽茂赂聫 Format email invalide (ex: nom@exemple.com)';
      } else {
        // V脙漏rifier la disponibilit脙漏 avec debounce
        clearTimeout(validationTimers[fieldName]);
        validationTimers[fieldName] = setTimeout(async () => {
          showLoading(`pro-${fieldName}-success`, 'V脙漏rification disponibilit脙漏...');
          
          try {
            const response = await fetch(`${window.API_BASE_URL}/user/exists?email=${encodeURIComponent(value)}`);
            
            // G脙漏rer les erreurs 502/503 du backend
            if (!response.ok) {
              if (response.status === 502 || response.status === 503) {
                console.warn('Backend temporairement indisponible pour v脙漏rification email');
                showSuccess(`pro-${fieldName}-success`, '芒聹聯 Format valide (v脙漏rification indisponible)');
                return; // Ne pas bloquer l'utilisateur
              }
              throw new Error(`HTTP ${response.status}`);
            }
            
            const data = await response.json();
            
            if (data.exists) {
              showError(`pro-${fieldName}-error`, '芒職聽茂赂聫 Cet email est d脙漏j脙聽 utilis脙漏');
              showSuccess(`pro-${fieldName}-success`, '');
              inputEl.classList.add('field-error');
            } else {
              showError(`pro-${fieldName}-error`, '');
              showSuccess(`pro-${fieldName}-success`, '芒聹聯 Email disponible');
              inputEl.classList.add('field-success');
            }
          } catch (error) {
            console.error('Erreur v脙漏rification email:', error);
            // En cas d'erreur, ne pas bloquer - juste afficher format valide
            showSuccess(`pro-${fieldName}-success`, '芒聹聯 Format valide');
          }
        }, 500);
        
        successMsg = '芒聹聯 Format valide';
      }
      break;
    
    case 'username':
      if (!value) {
        isValid = false;
        errorMsg = '芒職聽茂赂聫 Nom d\'utilisateur requis';
      } else if (value.length < 3) {
        isValid = false;
        errorMsg = '芒職聽茂赂聫 Minimum 3 caract脙篓res';
      } else if (value.length > 20) {
        isValid = false;
        errorMsg = '芒職聽茂赂聫 Maximum 20 caract脙篓res';
      } else if (!/^[a-zA-Z0-9_-]+$/.test(value)) {
        isValid = false;
        errorMsg = '芒職聽茂赂聫 Caract脙篓res autoris脙漏s: lettres, chiffres, _ et -';
      } else {
        // V脙漏rifier la disponibilit脙漏 avec debounce
        clearTimeout(validationTimers[fieldName]);
        validationTimers[fieldName] = setTimeout(async () => {
          showLoading(`pro-${fieldName}-success`, 'V脙漏rification disponibilit脙漏...');
          
          try {
            const response = await fetch(`${window.API_BASE_URL}/user/exists?username=${encodeURIComponent(value)}`);
            
            // G脙漏rer les erreurs 502/503 du backend
            if (!response.ok) {
              if (response.status === 502 || response.status === 503) {
                console.warn('Backend temporairement indisponible pour v脙漏rification username');
                showSuccess(`pro-${fieldName}-success`, '芒聹聯 Format valide (v脙漏rification indisponible)');
                return; // Ne pas bloquer l'utilisateur
              }
              throw new Error(`HTTP ${response.status}`);
            }
            
            const data = await response.json();
            
            if (data.exists) {
              showError(`pro-${fieldName}-error`, '芒職聽茂赂聫 Ce nom d\'utilisateur est d脙漏j脙聽 pris');
              showSuccess(`pro-${fieldName}-success`, '');
              inputEl.classList.add('field-error');
            } else {
              showError(`pro-${fieldName}-error`, '');
              showSuccess(`pro-${fieldName}-success`, '芒聹聯 Disponible');
              inputEl.classList.add('field-success');
            }
          } catch (error) {
            console.error('Erreur v脙漏rification username:', error);
            // En cas d'erreur, ne pas bloquer - juste afficher format valide
            showSuccess(`pro-${fieldName}-success`, '芒聹聯 Format valide');
          }
        }, 500);
        
        successMsg = '芒聹聯 Format valide';
      }
      break;
    
    case 'postalAddress':
      const skipAddress = document.getElementById('pro-skip-address')?.checked;
      if (!skipAddress && (!value || value.trim().length < 5)) {
        isValid = false;
        errorMsg = '芒職聽茂赂聫 Adresse compl脙篓te requise (minimum 5 caract脙篓res)';
      } else if (!skipAddress && value && value.trim().length < 5) {
        isValid = false;
        errorMsg = '芒職聽茂赂聫 Adresse trop courte (minimum 5 caract脙篓res)';
      } else if (!skipAddress && value) {
        successMsg = '芒聹聯 Adresse valide';
      }
      break;
  }

  if (errorMsg) {
    showError(`pro-${fieldName}-error`, errorMsg);
  } else if (successMsg && !validationTimers[fieldName]) {
    showSuccess(`pro-${fieldName}-success`, successMsg);
  }
  
  return isValid;
}

