// Toggle visibilit脙漏 mot de passe
function toggleProPasswordVisibility(inputId, event) {
  // 芒職聽茂赂聫芒職聽茂赂聫芒職聽茂赂聫 CRITIQUE : Emp脙陋cher la propagation pour 脙漏viter la fermeture du formulaire
  if (event) {
    event.preventDefault();
    event.stopPropagation();
    event.stopImmediatePropagation();
  }
  
  const input = document.getElementById(inputId);
  if (!input) {
    console.warn('[PASSWORD TOGGLE] Input non trouv脙漏:', inputId);
    return false;
  }
  
  if (input.type === 'password') {
    input.type = 'text';
  } else {
    input.type = 'password';
  }
  
  return false; // Emp脙陋cher tout comportement par d脙漏faut
}

