// G脙漏rer l'upload de photo pour OAuth
window.handleOAuthPhotoUpload = function(event) {
  const file = event.target.files[0];
  if (!file) return;
  
  // V脙漏rifier que c'est une image
  if (!file.type.startsWith('image/')) {
    document.getElementById('photo-upload-feedback').innerHTML = '<span style="color:var(--ui-text-error);">芒職聽茂赂聫 Veuillez s脙漏lectionner une image</span>';
    return;
  }
  
  // V脙漏rifier la taille (max 5MB)
  if (file.size > 5 * 1024 * 1024) {
    document.getElementById('photo-upload-feedback').innerHTML = '<span style="color:var(--ui-text-error);">芒職聽茂赂聫 L\'image est trop volumineuse (max 5MB)</span>';
    return;
  }
  
  // Afficher l'aper脙搂u
  const reader = new FileReader();
  reader.onload = function(e) {
    const previewContainer = document.getElementById('photo-preview-container');
    if (previewContainer) {
      previewContainer.innerHTML = `<img src="${e.target.result}" style="width:100%;height:100%;object-fit:cover;border-radius:50%;" alt="Photo preview">`;
    }
    
    // Activer le bouton d'upload
    const uploadBtn = document.getElementById('upload-photo-btn');
    if (uploadBtn) {
      uploadBtn.disabled = false;
      uploadBtn.style.background = 'linear-gradient(135deg,#00ffc3,#3b82f6)';
      uploadBtn.style.color = '#000';
      uploadBtn.style.cursor = 'pointer';
    }
    
    document.getElementById('photo-upload-feedback').innerHTML = '<span style="color:var(--ui-text-success);">芒聹聟 Photo s脙漏lectionn脙漏e</span>';
  };
  reader.readAsDataURL(file);
  
  // Stocker le fichier
  window.oauthPhotoFile = file;
};

// Uploader la photo pour OAuth
window.uploadOAuthPhoto = async function() {
  const file = window.oauthPhotoFile;
  const userData = window.oauthPhotoUploadData;
  
  if (!file || !userData) {
    showNotification('芒聺聦 Erreur: Fichier ou donn脙漏es utilisateur manquants', 'error');
    return;
  }
  
  const uploadBtn = document.getElementById('upload-photo-btn');
  const feedback = document.getElementById('photo-upload-feedback');
  
  if (uploadBtn) {
    uploadBtn.disabled = true;
    uploadBtn.textContent = 'Upload en cours...';
  }
  
  if (feedback) {
    feedback.innerHTML = '<span style="color:var(--ui-text-info);">芒聫鲁 Upload en cours...</span>';
  }
  
  try {
    // Convertir l'image en base64
    const reader = new FileReader();
    reader.onload = async function(e) {
      const base64Photo = e.target.result;
      
      // Appeler l'endpoint de compl脙漏tion OAuth avec la photo
      const response = await fetch(`${window.API_BASE_URL}/user/oauth/google/complete`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          userId: userData.id,
          email: userData.email,
          username: userData.username || userData.email?.split('@')[0]?.substring(0, 20),
          firstName: userData.firstName || userData.first_name || '',
          lastName: userData.lastName || userData.last_name || '',
          profilePhoto: base64Photo
        })
      });
      
      const result = await response.json();
      
      if (response.ok && result.ok) {
        // Mettre 脙聽 jour currentUser et UI
        if (result.user) {
          const slimUser = {
            id: result.user.id || userData.id,
            email: result.user.email || userData.email,
            username: result.user.username || userData.username,
            firstName: result.user.firstName || result.user.first_name || '',
            lastName: result.user.lastName || result.user.last_name || '',
            role: result.user.role || 'user',
            subscription: result.user.subscription || 'free',
            profile_photo_url: result.user.profile_photo_url || base64Photo,
            hasPassword: result.user.hasPassword || false,
            hasPostalAddress: result.user.hasPostalAddress || false,
            profileComplete: true,
            isLoggedIn: true
          };
          
          currentUser = { ...currentUser, ...slimUser, isLoggedIn: true };
          updateAuthUI(slimUser);
          
          try {
            const slimJson = JSON.stringify(slimUser);
            localStorage.setItem('currentUser', slimJson);
          } catch (e) {
            try { sessionStorage.setItem('currentUser', slimJson); } catch (e2) {}
          }
        }
        
        closeAuthModal();
        closePublishModal();
        
        // Si besoin confirmation email, afficher le modal
        if (result.needsEmailVerification) {
          showEmailVerificationModal(userData.email, userData.username || 'Utilisateur');
        } else {
          const displayName = userData.username || userData.firstName || userData.email?.split('@')[0] || 'Utilisateur';
          showNotification(`芒聹聟 Bienvenue ${displayName} ! Vous 脙陋tes connect脙漏.`, 'success');
        }
        
        // Nettoyer
        delete window.oauthPhotoFile;
        delete window.oauthPhotoUploadData;
      } else {
        throw new Error(result.error || 'Erreur lors de l\'upload de la photo');
      }
    };
    reader.readAsDataURL(file);
  } catch (error) {
    console.error('芒聺聦 Erreur upload photo OAuth:', error);
    if (feedback) {
      feedback.innerHTML = `<span style="color:var(--ui-text-error);">芒聺聦 ${error.message || 'Erreur lors de l\'upload'}</span>`;
    }
    if (uploadBtn) {
      uploadBtn.disabled = false;
      uploadBtn.textContent = 'Ajouter la photo';
    }
    showNotification(`芒聺聦 ${error.message || 'Erreur lors de l\'upload de la photo'}`, 'error');
  }
};

// Passer l'脙漏tape photo (rediriger vers le formulaire complet)
window.skipPhotoUpload = function() {
  const userData = window.oauthPhotoUploadData;
  if (!userData) {
    closeAuthModal();
    return;
  }
  
  // Fermer le modal photo et afficher le formulaire complet d'inscription
  closeAuthModal();
  
  // Afficher le formulaire d'inscription complet avec les donn脙漏es Google pr脙漏-remplies
  if (typeof showProRegisterForm === 'function') {
    showProRegisterForm();
  } else if (typeof window.showProRegisterForm === 'function') {
    window.showProRegisterForm();
  }
  
  // Pr脙漏-remplir avec les donn脙漏es Google
  window.registerData = {
    email: userData.email || '',
    username: userData.username || userData.email?.split('@')[0]?.substring(0, 20) || '',
    password: '',
    passwordConfirm: '',
    firstName: userData.firstName || userData.first_name || '',
    lastName: userData.lastName || userData.last_name || '',
    profilePhoto: '', // Photo 脙聽 ajouter dans le formulaire complet
    postalAddress: '',
    avatarId: 1,
    avatarDescription: '',
    addresses: [],
    emailVerificationCode: null,
    emailVerified: false,
    verificationAttempts: 0,
    lastVerificationAttempt: null,
    registrationAttempts: 0,
    lastRegistrationAttempt: null,
    captchaAnswer: null,
    codeSentAt: null,
    codeExpiresAt: null,
    resendCountdown: 0,
    lastResendAttempt: null
  };
  
  showNotification('芒職聽茂赂聫 Une photo de profil est obligatoire. Veuillez compl脙漏ter votre profil.', 'warning');
  
  // Nettoyer
  delete window.oauthPhotoFile;
  delete window.oauthPhotoUploadData;
};

