// Gestion de la saisie du code de v脙漏rification
window.handleEmailCodeInput = function(index, event) {
  const input = event.target;
  const value = input.value.replace(/[^0-9]/g, '');
  input.value = value;
  
  if (value && index < 5) {
    const nextInput = document.getElementById(`email-code-digit-${index + 1}`);
    if (nextInput) nextInput.focus();
  }
  
  // V脙漏rifier si tous les champs sont remplis
  checkEmailCodeComplete();
};

window.handleEmailCodeKeydown = function(index, event) {
  if (event.key === 'Backspace' && !event.target.value && index > 0) {
    const prevInput = document.getElementById(`email-code-digit-${index - 1}`);
    if (prevInput) prevInput.focus();
  }
};

function checkEmailCodeComplete() {
  let code = '';
  for (let i = 0; i < 6; i++) {
    const input = document.getElementById(`email-code-digit-${i}`);
    if (input) code += input.value;
  }
  
  if (code.length === 6) {
    verifyEmailCode(code);
  }
}

// V脙漏rifier le code d'email
async function verifyEmailCode(providedCode) {
  if (!providedCode) {
    // R脙漏cup脙漏rer le code depuis les inputs
    let code = '';
    for (let i = 0; i < 6; i++) {
      const input = document.getElementById(`email-code-digit-${i}`);
      if (input) code += input.value;
    }
    providedCode = code;
  }
  
  if (providedCode.length !== 6) {
    showNotification('芒職聽茂赂聫 Veuillez entrer un code 脙聽 6 chiffres', 'warning');
    return;
  }
  
  const feedbackEl = document.getElementById('email-code-feedback');
  if (feedbackEl) {
    feedbackEl.textContent = 'V脙漏rification en cours...';
    feedbackEl.style.color = 'var(--ui-text-muted)';
  }
  
  try {
    // V脙漏rifier le code via le backend
    const response = await fetch(`${window.API_BASE_URL}/user/verify-email`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        email: window.pendingEmailVerification?.email,
        code: providedCode
      })
    });
    
    if (response.ok) {
      const data = await response.json();
      
      // Marquer l'email comme v脙漏rifi脙漏
      if (currentUser) {
        currentUser.emailVerified = true;
        safeSetItem('currentUser', JSON.stringify(currentUser));
      }
      
      // Afficher le succ脙篓s
      if (feedbackEl) {
        feedbackEl.textContent = '芒聹聟 Email v脙漏rifi脙漏 avec succ脙篓s !';
        feedbackEl.style.color = '#22c55e';
      }
      
      // Mettre 脙聽 jour les inputs en vert
      for (let i = 0; i < 6; i++) {
        const input = document.getElementById(`email-code-digit-${i}`);
        if (input) {
          input.style.borderColor = '#22c55e';
          input.style.background = 'rgba(34,197,94,0.1)';
        }
      }
      
      showNotification('芒聹聟 Email v脙漏rifi脙漏 avec succ脙篓s !', 'success');
      
      // Fermer le modal et mettre 脙聽 jour le bloc compte
      setTimeout(() => {
        closeAuthModal();
        if (typeof updateAccountBlockLegitimately === 'function') {
          updateAccountBlockLegitimately();
        }
      }, 1000);
    } else {
      const errorData = await response.json().catch(() => ({}));
      if (feedbackEl) {
        feedbackEl.textContent = errorData.error || 'Code incorrect';
        feedbackEl.style.color = '#ef4444';
      }
      
      // Mettre 脙聽 jour les inputs en rouge
      for (let i = 0; i < 6; i++) {
        const input = document.getElementById(`email-code-digit-${i}`);
        if (input) {
          input.style.borderColor = '#ef4444';
          input.style.background = 'rgba(239,68,68,0.1)';
        }
      }
      
      showNotification('芒聺聦 Code incorrect. Veuillez r脙漏essayer.', 'error');
    }
  } catch (error) {
    console.error('[EMAIL VERIFICATION] Erreur:', error);
    if (feedbackEl) {
      feedbackEl.textContent = 'Erreur de connexion. Veuillez r脙漏essayer.';
      feedbackEl.style.color = '#ef4444';
    }
    showNotification('芒聺聦 Erreur de connexion. Veuillez r脙漏essayer.', 'error');
  }
}

// Renvoyer le code de v脙漏rification
async function resendEmailVerificationCode() {
  if (!window.pendingEmailVerification) {
    showNotification('芒職聽茂赂聫 Aucune v脙漏rification en cours', 'warning');
    return;
  }
  
  const { email } = window.pendingEmailVerification;
  const newCode = Math.floor(100000 + Math.random() * 900000).toString();
  
  window.pendingEmailVerification.code = newCode;
  window.pendingEmailVerification.expiresAt = Date.now() + (15 * 60 * 1000);
  
  try {
    await fetch(`${window.API_BASE_URL}/user/send-verification-code`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email, code: newCode })
    });
    
    showNotification('芒聹聟 Code renvoy脙漏 ! V脙漏rifiez votre bo脙庐te email.', 'success');
    
    // En mode d脙漏veloppement, afficher le code
    if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
      console.log(`冒聼聰聬 NOUVEAU CODE DE V脙聣RIFICATION (DEV ONLY): ${newCode}`);
    }
  } catch (error) {
    console.error('[EMAIL VERIFICATION] Erreur renvoi code:', error);
    showNotification('芒職聽茂赂聫 Erreur lors du renvoi du code', 'error');
  }
}

