// VALIDATION EN TEMPS R脙聣EL
function validateEmailRealTime(email) {
  const emailInput = document.getElementById("register-email");
  const statusEl = document.getElementById("email-status");
  const feedbackEl = document.getElementById("email-feedback");
  
  if (!email || email.trim() === '') {
    if (statusEl) statusEl.textContent = '';
    if (feedbackEl) feedbackEl.textContent = '';
    if (emailInput) emailInput.style.borderColor = 'var(--ui-card-border)';
    return false;
  }
  
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isValid = emailRegex.test(email);
  
  if (statusEl) {
    statusEl.textContent = isValid ? '芒聹聟' : '芒聺聦';
    statusEl.style.color = isValid ? '#22c55e' : '#ef4444';
  }
  
  if (feedbackEl) {
    if (isValid) {
      feedbackEl.textContent = '';
      feedbackEl.style.color = '#22c55e';
    } else {
      feedbackEl.textContent = 'Format d\'email invalide';
      feedbackEl.style.color = '#ef4444';
    }
  }
  
  if (emailInput) {
    emailInput.style.borderColor = isValid ? '#22c55e' : '#ef4444';
  }
  
  return isValid;
}

function validateUsernameRealTime(username) {
  const usernameInput = document.getElementById("register-username");
  const statusEl = document.getElementById("username-status");
  const feedbackEl = document.getElementById("username-feedback");
  
  if (!username || username.trim() === '') {
    if (statusEl) statusEl.textContent = '';
    if (feedbackEl) feedbackEl.textContent = '';
    if (usernameInput) usernameInput.style.borderColor = 'var(--ui-card-border)';
    return false;
  }
  
  const usernameRegex = /^[a-zA-Z0-9_-]{3,20}$/;
  const isValid = usernameRegex.test(username);
  
  if (statusEl) {
    statusEl.textContent = isValid ? '芒聹聟' : '芒聺聦';
    statusEl.style.color = isValid ? '#22c55e' : '#ef4444';
  }
  
  if (feedbackEl) {
    if (isValid) {
      feedbackEl.textContent = '';
      feedbackEl.style.color = '#22c55e';
    } else {
      if (username.length < 3) {
        feedbackEl.textContent = 'Minimum 3 caract脙篓res';
      } else if (username.length > 20) {
        feedbackEl.textContent = 'Maximum 20 caract脙篓res';
      } else {
        feedbackEl.textContent = 'Caract脙篓res autoris脙漏s : lettres, chiffres, _ et -';
      }
      feedbackEl.style.color = '#ef4444';
    }
  }
  
  if (usernameInput) {
    usernameInput.style.borderColor = isValid ? '#22c55e' : '#ef4444';
  }
  
  return isValid;
}

function checkPasswordStrength(password) {
  const passwordInput = document.getElementById("register-password");
  const strengthBar = document.getElementById("password-strength-fill");
  const strengthLabel = document.getElementById("password-strength-label");
  const feedbackEl = document.getElementById("password-feedback");
  const requirements = {
    length: document.getElementById("req-length"),
    upper: document.getElementById("req-upper"),
    lower: document.getElementById("req-lower"),
    number: document.getElementById("req-number"),
    special: document.getElementById("req-special")
  };
  
  if (!password || password.length === 0) {
    if (strengthBar) strengthBar.style.width = '0%';
    if (strengthLabel) strengthLabel.textContent = '';
    if (feedbackEl) feedbackEl.textContent = '';
    Object.values(requirements).forEach(el => {
      if (el) el.style.color = 'var(--ui-text-muted)';
    });
    if (passwordInput) passwordInput.style.borderColor = 'var(--ui-card-border)';
    return 0;
  }
  
  // V脙漏rifier les crit脙篓res
  const hasLength = password.length >= 8;
  const hasUpper = /[A-Z]/.test(password);
  const hasLower = /[a-z]/.test(password);
  const hasNumber = /[0-9]/.test(password);
  const hasSpecial = /[!@#$%^&*(),.?":{}|<>]/.test(password);
  
  // Mettre 脙聽 jour les indicateurs de crit脙篓res
  if (requirements.length) requirements.length.style.color = hasLength ? '#22c55e' : 'var(--ui-text-muted)';
  if (requirements.upper) requirements.upper.style.color = hasUpper ? '#22c55e' : 'var(--ui-text-muted)';
  if (requirements.lower) requirements.lower.style.color = hasLower ? '#22c55e' : 'var(--ui-text-muted)';
  if (requirements.number) requirements.number.style.color = hasNumber ? '#22c55e' : 'var(--ui-text-muted)';
  if (requirements.special) requirements.special.style.color = hasSpecial ? '#22c55e' : 'var(--ui-text-muted)';
  
  // Calculer la force (0-100)
  const criteriaMet = [hasLength, hasUpper, hasLower, hasNumber, hasSpecial].filter(Boolean).length;
  const strength = (criteriaMet / 5) * 100;
  
  // D脙漏terminer le niveau de force
  let strengthText = '';
  let strengthColor = '#ef4444';
  
  if (strength < 40) {
    strengthText = 'Faible';
    strengthColor = '#ef4444';
  } else if (strength < 60) {
    strengthText = 'Moyen';
    strengthColor = '#f59e0b';
  } else if (strength < 80) {
    strengthText = 'Fort';
    strengthColor = '#3b82f6';
  } else {
    strengthText = 'Tr脙篓s fort';
    strengthColor = '#22c55e';
  }
  
  // Mettre 脙聽 jour la barre et le label
  if (strengthBar) {
    strengthBar.style.width = strength + '%';
    strengthBar.style.background = strengthColor;
  }
  
  if (strengthLabel) {
    strengthLabel.textContent = strengthText;
    strengthLabel.style.color = strengthColor;
  }
  
  if (feedbackEl) {
    feedbackEl.textContent = `${criteriaMet}/5 crit脙篓res remplis`;
    feedbackEl.style.color = strengthColor;
  }
  
  if (passwordInput) {
    passwordInput.style.borderColor = strength >= 60 ? '#22c55e' : strength >= 40 ? '#f59e0b' : '#ef4444';
  }
  
  return strength;
}

function togglePasswordVisibility() {
  const passwordInput = document.getElementById("register-password");
  if (!passwordInput) return;
  
  if (passwordInput.type === 'password') {
    passwordInput.type = 'text';
  } else {
    passwordInput.type = 'password';
  }
}

// Validation du nom/pr脙漏nom en temps r脙漏el
function validateNameRealTime(type, value) {
  const inputId = type === 'firstname' ? 'register-firstname' : 'register-lastname';
  const statusId = type === 'firstname' ? 'firstname-status' : 'lastname-status';
  const feedbackId = type === 'firstname' ? 'firstname-feedback' : 'lastname-feedback';
  
  const nameInput = document.getElementById(inputId);
  const statusEl = document.getElementById(statusId);
  const feedbackEl = document.getElementById(feedbackId);
  
  if (!value || value.trim() === '') {
    if (statusEl) statusEl.textContent = '';
    if (feedbackEl) feedbackEl.textContent = '';
    if (nameInput) nameInput.style.borderColor = 'var(--ui-card-border)';
    return false;
  }
  
  const trimmed = value.trim();
  
  // V脙漏rifier que ce n'est pas juste des caract脙篓res al脙漏atoires
  // Un nom/pr脙漏nom valide doit avoir au moins 2 caract脙篓res et contenir principalement des lettres
  const nameRegex = /^[a-zA-Z脙聽脙隆脙垄脙陇脙拢脙楼脙篓脙漏脙陋脙芦脙卢脙颅脙庐脙炉脙虏脙鲁脙麓脙露脙碌脙鹿脙潞脙禄脙录脙陆脙驴脙卤脙搂脙聙脙聛脙聜脙聞脙聝脙聟脙聢脙聣脙聤脙聥脙聦脙聧脙聨脙聫脙聮脙聯脙聰脙聳脙聲脙聶脙職脙聸脙聹脙聺脜赂脙聭脙聡\s-]{2,30}$/;
  const isValid = nameRegex.test(trimmed) && trimmed.length >= 2 && trimmed.length <= 30;
  
  // V脙漏rifier qu'il n'y a pas trop de caract脙篓res sp脙漏ciaux ou de chiffres
  const hasTooManyNumbers = (trimmed.match(/\d/g) || []).length > trimmed.length * 0.1; // Max 10% de chiffres
  const hasTooManySpecial = (trimmed.match(/[^a-zA-Z脙聽脙隆脙垄脙陇脙拢脙楼脙篓脙漏脙陋脙芦脙卢脙颅脙庐脙炉脙虏脙鲁脙麓脙露脙碌脙鹿脙潞脙禄脙录脙陆脙驴脙卤脙搂脙聙脙聛脙聜脙聞脙聝脙聟脙聢脙聣脙聤脙聥脙聦脙聧脙聨脙聫脙聮脙聯脙聰脙聳脙聲脙聶脙職脙聸脙聹脙聺脜赂脙聭脙聡\s-]/g) || []).length > 0;
  
  // V脙漏rifier qu'il y a au moins une majuscule (nom propre)
  const hasCapital = /[A-Z脙聙脙聛脙聜脙聞脙聝脙聟脙聢脙聣脙聤脙聥脙聦脙聧脙聨脙聫脙聮脙聯脙聰脙聳脙聲脙聶脙職脙聸脙聹脙聺脜赂脙聭脙聡]/.test(trimmed);
  
  // V脙漏rifier que c'est principalement des lettres (au moins 70%)
  const letterCount = (trimmed.match(/[a-zA-Z脙聽脙隆脙垄脙陇脙拢脙楼脙篓脙漏脙陋脙芦脙卢脙颅脙庐脙炉脙虏脙鲁脙麓脙露脙碌脙鹿脙潞脙禄脙录脙陆脙驴脙卤脙搂脙聙脙聛脙聜脙聞脙聝脙聟脙聢脙聣脙聤脙聥脙聦脙聧脙聨脙聫脙聮脙聯脙聰脙聳脙聲脙聶脙職脙聸脙聹脙聺脜赂脙聭脙聡]/g) || []).length;
  const isMostlyLetters = letterCount >= trimmed.length * 0.7;
  
  const finalValid = isValid && !hasTooManyNumbers && !hasTooManySpecial && hasCapital && isMostlyLetters;
  
  if (statusEl) {
    statusEl.textContent = finalValid ? '芒聹聟' : '芒聺聦';
    statusEl.style.color = finalValid ? '#22c55e' : '#ef4444';
  }
  
  if (feedbackEl) {
    if (finalValid) {
      feedbackEl.textContent = '';
      feedbackEl.style.color = '#22c55e';
    } else {
      if (trimmed.length < 2) {
        feedbackEl.textContent = 'Minimum 2 caract脙篓res';
      } else if (trimmed.length > 30) {
        feedbackEl.textContent = 'Maximum 30 caract脙篓res';
      } else if (!hasCapital) {
        feedbackEl.textContent = 'Doit commencer par une majuscule';
      } else if (hasTooManyNumbers) {
        feedbackEl.textContent = 'Un nom ne doit pas contenir de chiffres';
      } else if (hasTooManySpecial) {
        feedbackEl.textContent = 'Caract脙篓res sp脙漏ciaux non autoris脙漏s';
      } else if (!isMostlyLetters) {
        feedbackEl.textContent = 'Doit contenir principalement des lettres';
      } else {
        feedbackEl.textContent = 'Format invalide';
      }
      feedbackEl.style.color = '#ef4444';
    }
  }
  
  if (nameInput) {
    nameInput.style.borderColor = finalValid ? '#22c55e' : '#ef4444';
  }
  
  return finalValid;
}

async function validateStep2() {
  const firstName = document.getElementById("register-firstname")?.value.trim();
  const lastName = document.getElementById("register-lastname")?.value.trim();
  const email = document.getElementById("register-email")?.value.trim();
  const username = document.getElementById("register-username")?.value.trim();
  const password = document.getElementById("register-password")?.value;
  const avatarDesc = document.getElementById("register-avatar-desc")?.value.trim() || '';
  const acceptTerms = document.getElementById("accept-terms")?.checked;
  
  // Validation pr脙漏nom
  if (!firstName || !validateNameRealTime('firstname', firstName)) {
    showNotification("芒職聽茂赂聫 Veuillez entrer un pr脙漏nom valide (2-30 caract脙篓res, lettres uniquement)", "warning");
    return;
  }
  
  // Validation nom
  if (!lastName || !validateNameRealTime('lastname', lastName)) {
    showNotification("芒職聽茂赂聫 Veuillez entrer un nom valide (2-30 caract脙篓res, lettres uniquement)", "warning");
    return;
  }
  
  // Validation email
  if (!email || !validateEmailRealTime(email)) {
    showNotification("芒職聽茂赂聫 Veuillez entrer une adresse email valide", "warning");
    return;
  }
  
  // Validation username
  if (!username || !validateUsernameRealTime(username)) {
    showNotification("芒職聽茂赂聫 Le nom d'utilisateur doit contenir 3-20 caract脙篓res (lettres, chiffres, _ et -)", "warning");
    return;
  }
  
  // Validation mot de passe
  if (!password) {
    showNotification("芒職聽茂赂聫 Veuillez entrer un mot de passe", "warning");
    return;
  }
  
  const passwordStrength = checkPasswordStrength(password);
  if (passwordStrength < 40) {
    showNotification("芒職聽茂赂聫 Le mot de passe est trop faible. Veuillez renforcer votre mot de passe.", "warning");
    return;
  }
  
  // Validation avatar
  if (!window.registerData.avatarId) {
    showNotification("芒職聽茂赂聫 Veuillez choisir un avatar", "warning");
    return;
  }
  
  // Validation CGU
  if (!acceptTerms) {
    showNotification("芒職聽茂赂聫 Vous devez accepter les Conditions d'utilisation et la Politique de confidentialit脙漏", "warning");
    return;
  }
  
  // V脙漏rifier le rate limiting
  const now = Date.now();
  if (window.registerData.lastRegistrationAttempt && (now - window.registerData.lastRegistrationAttempt) < 60000) {
    const remainingSeconds = Math.ceil((60000 - (now - window.registerData.lastRegistrationAttempt)) / 1000);
    showNotification(`芒聫卤茂赂聫 Veuillez patienter ${remainingSeconds} secondes avant de r脙漏essayer`, "warning");
    return;
  }
  
  window.registerData.firstName = firstName;
  window.registerData.lastName = lastName;
  window.registerData.email = email;
  window.registerData.username = username;
  window.registerData.password = password;
  window.registerData.avatarDescription = avatarDesc;
  window.registerData.lastRegistrationAttempt = now;
  window.registerData.registrationAttempts++;
  
  // V脙漏rifier si l'email existe d脙漏j脙聽
  try {
    const checkResponse = await fetch(`${window.API_BASE_URL}/user/check-email`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email: email })
    });
    
    if (checkResponse.ok) {
      const checkData = await checkResponse.json();
      if (checkData.exists) {
        showNotification("芒職聽茂赂聫 Cet email est d脙漏j脙聽 utilis脙漏. Veuillez vous connecter ou utiliser un autre email.", "warning");
        return;
      }
    }
  } catch (error) {
    console.error('Erreur v脙漏rification email:', error);
    // Continuer m脙陋me si la v脙漏rification 脙漏choue
  }
  
  // Passer 脙聽 l'脙漏tape de v脙漏rification d'email
  showRegisterStep2_5();
}

