// G脙漏n脙漏rer un CAPTCHA simple
function generateCaptcha() {
  const num1 = Math.floor(Math.random() * 10) + 1;
  const num2 = Math.floor(Math.random() * 10) + 1;
  const operators = ['+', '-', '脙聴'];
  const operator = operators[Math.floor(Math.random() * operators.length)];
  
  let question = '';
  let answer = 0;
  
  if (operator === '+') {
    question = `${num1} + ${num2} = ?`;
    answer = num1 + num2;
  } else if (operator === '-') {
    question = `${num1} - ${num2} = ?`;
    answer = num1 - num2;
  } else {
    question = `${num1} 脙聴 ${num2} = ?`;
    answer = num1 * num2;
  }
  
  window.registerData.captchaAnswer = answer;
  
  const questionEl = document.getElementById("captcha-question");
  if (questionEl) {
    questionEl.textContent = question;
  }
}

// G脙漏rer la saisie du code
function handleCodeInput(index, value) {
  if (!/^\d$/.test(value) && value !== '') return;
  
  const currentInput = document.getElementById(`code-digit-${index}`);
  if (currentInput && value) {
    currentInput.value = value;
    currentInput.style.borderColor = '#3b82f6';
    
    // Passer au champ suivant
    if (index < 5) {
      const nextInput = document.getElementById(`code-digit-${index + 1}`);
      if (nextInput) {
        nextInput.focus();
      }
    }
  }
  
  // V脙漏rifier si tous les champs sont remplis
  checkCodeComplete();
}

function handleCodeKeydown(index, event) {
  if (event.key === 'Backspace' && !event.target.value && index > 0) {
    const prevInput = document.getElementById(`code-digit-${index - 1}`);
    if (prevInput) {
      prevInput.focus();
      prevInput.value = '';
    }
  }
}

function checkCodeComplete() {
  let code = '';
  for (let i = 0; i < 6; i++) {
    const input = document.getElementById(`code-digit-${i}`);
    if (input && input.value) {
      code += input.value;
    } else {
      return false;
    }
  }
  
  // Auto-v脙漏rification si le code est complet
  if (code.length === 6) {
    verifyEmailCode(code);
  }
  
  return true;
}

// Envoyer le code de v脙漏rification
async function sendVerificationCode() {
  try {
    showNotification("冒聼聯搂 Envoi du code de v脙漏rification...", "info");
    
    // G脙漏n脙漏rer un code 脙聽 6 chiffres
    const code = Math.floor(100000 + Math.random() * 900000).toString();
    window.window.registerData.emailVerificationCode = code;
    window.registerData.codeSentAt = Date.now();
    window.registerData.codeExpiresAt = Date.now() + (15 * 60 * 1000); // 15 minutes
    
    // Envoyer via le backend
    const response = await fetch(`${window.API_BASE_URL}/user/send-verification-code`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        email: window.registerData.email,
        code: code,
        username: window.registerData.username
      })
    });
    
    if (response.ok) {
      showNotification("芒聹聟 Code envoy脙漏 ! V脙漏rifiez votre bo脙庐te email.", "success");
      
      // En mode d脙漏veloppement, afficher le code dans la console
      if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
        console.log(`冒聼聰聬 CODE DE V脙聣RIFICATION (DEV ONLY): ${code}`);
      }
    } else {
      // En cas d'erreur backend, utiliser le code g脙漏n脙漏r脙漏 localement
      console.warn('Backend non disponible, utilisation du code local');
      showNotification("芒聹聟 Code g脙漏n脙漏r脙漏 ! (Mode d脙漏veloppement)", "success");
      console.log(`冒聼聰聬 CODE DE V脙聣RIFICATION (DEV ONLY): ${code}`);
    }
  } catch (error) {
    console.error('Erreur envoi code:', error);
    // En cas d'erreur, g脙漏n脙漏rer quand m脙陋me un code pour le d脙漏veloppement
    const code = Math.floor(100000 + Math.random() * 900000).toString();
    window.window.registerData.emailVerificationCode = code;
    window.registerData.codeSentAt = Date.now();
    window.registerData.codeExpiresAt = Date.now() + (15 * 60 * 1000);
    showNotification("芒聹聟 Code g脙漏n脙漏r脙漏 ! (Mode d脙漏veloppement - v脙漏rifiez la console)", "info");
    console.log(`冒聼聰聬 CODE DE V脙聣RIFICATION (DEV ONLY): ${code}`);
  }
}

// Renvoyer le code
async function resendVerificationCode() {
  const now = Date.now();
  const lastResend = window.registerData.lastResendAttempt || 0;
  
  // Rate limiting : 60 secondes entre chaque renvoi
  if (now - lastResend < 60000) {
    const remaining = Math.ceil((60000 - (now - lastResend)) / 1000);
    showNotification(`芒聫卤茂赂聫 Veuillez patienter ${remaining} secondes avant de renvoyer`, "warning");
    return;
  }
  
  window.registerData.lastResendAttempt = now;
  window.window.registerData.emailVerificationCode = null; // R脙漏initialiser
  
  await sendVerificationCode();
  
  // D脙漏marrer le countdown
  window.registerData.resendCountdown = 60;
  startResendCountdown(60);
}

function startResendCountdown(seconds) {
  const resendButton = document.getElementById("resend-button");
  const countdownEl = document.getElementById("resend-countdown");
  
  if (!resendButton || !countdownEl) return;
  
  resendButton.disabled = true;
  resendButton.style.opacity = '0.5';
  resendButton.style.cursor = 'not-allowed';
  
  let remaining = seconds;
  
  const interval = setInterval(() => {
    remaining--;
    window.registerData.resendCountdown = remaining;
    
    if (countdownEl) {
      countdownEl.textContent = `Vous pourrez renvoyer dans ${remaining} secondes`;
    }
    
    if (remaining <= 0) {
      clearInterval(interval);
      resendButton.disabled = false;
      resendButton.style.opacity = '1';
      resendButton.style.cursor = 'pointer';
      if (countdownEl) countdownEl.textContent = '';
      window.registerData.resendCountdown = 0;
    }
  }, 1000);
}

// V脙漏rifier le code
async function verifyEmailCode(providedCode) {
  // V脙漏rifier le CAPTCHA d'abord
  const captchaInput = document.getElementById("captcha-answer");
  const captchaFeedback = document.getElementById("captcha-feedback");
  
  if (!captchaInput || !captchaInput.value) {
    if (captchaFeedback) {
      captchaFeedback.textContent = "芒職聽茂赂聫 Veuillez r脙漏pondre au CAPTCHA";
      captchaFeedback.style.color = "#ef4444";
    }
    return;
  }
  
  const captchaAnswer = parseInt(captchaInput.value.trim());
  if (captchaAnswer !== window.registerData.captchaAnswer) {
    if (captchaFeedback) {
      captchaFeedback.textContent = "芒聺聦 R脙漏ponse incorrecte";
      captchaFeedback.style.color = "#ef4444";
    }
    generateCaptcha(); // R脙漏g脙漏n脙漏rer le CAPTCHA
    captchaInput.value = '';
    return;
  }
  
  if (captchaFeedback) {
    captchaFeedback.textContent = "芒聹聟 CAPTCHA correct";
    captchaFeedback.style.color = "#22c55e";
  }
  
  // R脙漏cup脙漏rer le code saisi
  if (!providedCode) {
    providedCode = '';
    for (let i = 0; i < 6; i++) {
      const input = document.getElementById(`code-digit-${i}`);
      if (input) {
        providedCode += input.value || '';
      }
    }
  }
  
  if (providedCode.length !== 6) {
    const feedbackEl = document.getElementById("code-feedback");
    if (feedbackEl) {
      feedbackEl.textContent = "芒職聽茂赂聫 Veuillez entrer les 6 chiffres";
      feedbackEl.style.color = "#ef4444";
    }
    return;
  }
  
  // V脙漏rifier le rate limiting
  const now = Date.now();
  if (window.registerData.lastVerificationAttempt) {
    const timeSinceLastAttempt = now - window.registerData.lastVerificationAttempt;
    if (timeSinceLastAttempt < 2000) { // 2 secondes entre chaque tentative
      showNotification("芒聫卤茂赂聫 Veuillez patienter avant de r脙漏essayer", "warning");
      return;
    }
  }
  
  window.registerData.lastVerificationAttempt = now;
  window.registerData.verificationAttempts++;
  
  // V脙漏rifier si le code a expir脙漏
  if (window.registerData.codeExpiresAt && now > window.registerData.codeExpiresAt) {
    showNotification("芒聫掳 Le code a expir脙漏. Veuillez en demander un nouveau.", "warning");
    window.window.registerData.emailVerificationCode = null;
    return;
  }
  
  // V脙漏rifier le code
  if (providedCode === window.window.registerData.emailVerificationCode) {
    window.window.registerData.emailVerified = true;
    
    // Mettre 脙聽 jour l'affichage
    for (let i = 0; i < 6; i++) {
      const input = document.getElementById(`code-digit-${i}`);
      if (input) {
        input.style.borderColor = '#22c55e';
        input.style.background = 'rgba(34,197,94,0.1)';
      }
    }
    
    const feedbackEl = document.getElementById("code-feedback");
    if (feedbackEl) {
      feedbackEl.textContent = "芒聹聟 Code v脙漏rifi脙漏 avec succ脙篓s !";
      feedbackEl.style.color = "#22c55e";
    }
    
    showNotification("芒聹聟 Email v脙漏rifi脙漏 !", "success");
    
    // Passer 脙聽 l'脙漏tape suivante apr脙篓s un court d脙漏lai
    setTimeout(() => {
      showRegisterStep3();
    }, 1000);
  } else {
    // Code incorrect
    window.registerData.verificationAttempts++;
    
    // Bloquer apr脙篓s 5 tentatives
    if (window.registerData.verificationAttempts >= 5) {
      showNotification("冒聼職芦 Trop de tentatives 脙漏chou脙漏es. Veuillez renvoyer un nouveau code.", "error");
      window.window.registerData.emailVerificationCode = null;
      window.registerData.verificationAttempts = 0;
      showRegisterStep2_5();
      return;
    }
    
    // Afficher l'erreur
    const feedbackEl = document.getElementById("code-feedback");
    if (feedbackEl) {
      feedbackEl.textContent = `芒聺聦 Code incorrect (${window.registerData.verificationAttempts}/5 tentatives)`;
      feedbackEl.style.color = "#ef4444";
    }
    
    // Effacer les champs
    for (let i = 0; i < 6; i++) {
      const input = document.getElementById(`code-digit-${i}`);
      if (input) {
        input.value = '';
        input.style.borderColor = '#ef4444';
        setTimeout(() => {
          input.style.borderColor = 'var(--ui-card-border)';
        }, 1000);
      }
    }
    
    // Focus sur le premier champ
    const firstInput = document.getElementById("code-digit-0");
    if (firstInput) firstInput.focus();
    
    updateCodeAttemptsDisplay();
  }
}

function updateCodeAttemptsDisplay() {
  const attemptsEl = document.getElementById("code-attempts");
  if (attemptsEl && window.registerData.verificationAttempts > 0) {
    attemptsEl.textContent = `${window.registerData.verificationAttempts}/5 tentatives utilis脙漏es`;
    attemptsEl.style.color = window.registerData.verificationAttempts >= 3 ? "#ef4444" : "var(--ui-text-muted)";
  }
}

