function addAddressField() {
  if (window.registerData.addresses.length >= 2) {
    showNotification("芒職聽茂赂聫 Maximum 2 adresses autoris脙漏es", "warning");
    return;
  }
  
  window.registerData.addresses.push({ address: '', city: '', lat: null, lng: null, isPrimary: false });
  showRegisterStep3();
}

function removeAddressField(index) {
  if (window.registerData.addresses.length <= 1) {
    showNotification("芒職聽茂赂聫 Au moins une adresse est requise", "warning");
    return;
  }
  
  window.registerData.addresses.splice(index, 1);
  showRegisterStep3();
}

async function geocodeAddress(addressIndex) {
  const addressInput = document.getElementById(`address-${addressIndex}`);
  const cityInput = document.getElementById(`city-${addressIndex}`);
  
  if (!addressInput || !cityInput) return;
  
  const address = addressInput.value.trim();
  const city = cityInput.value.trim();
  
  if (!address || !city) {
    showNotification("芒職聽茂赂聫 Veuillez remplir l'adresse et la ville", "warning");
    return;
  }
  
  const fullAddress = `${address}, ${city}, Switzerland`;
  
  try {
    showNotification("冒聼聰聧 V脙漏rification de l'adresse...", "info");
    
    // Utiliser Nominatim avec plus de d脙漏tails pour v脙漏rifier que l'adresse est r脙漏elle
    // VALIDATION STRICTE + PERFORMANCE: Param脙篓tres optimis脙漏s pour recherche rapide et exacte
    // 芒職聽茂赂聫芒職聽茂赂聫芒職聽茂赂聫 RECHERCHE MONDIALE - Pas de restriction de pays, support multilingue
    const langCode = (navigator.language || 'fr').split('-')[0];
    const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(fullAddress)}&limit=10&addressdetails=1&extratags=1&accept-language=${langCode},en&dedupe=1`, {
      headers: {
        'User-Agent': 'MapEventAI/1.0',
        'Accept-Language': `${langCode},en,fr`
      }
    });
    
    if (!response.ok) {
      throw new Error('Erreur de g脙漏ocodage');
    }
    
    const data = await response.json();
    
    if (data.length === 0) {
      showNotification("芒職聽茂赂聫 Adresse introuvable. Veuillez v脙漏rifier que l'adresse existe r脙漏ellement.", "warning");
      return;
    }
    
    // Prendre le r脙漏sultat le plus pertinent (g脙漏n脙漏ralement le premier)
    const result = data[0];
    
    // V脙漏rifier que le r脙漏sultat correspond bien 脙聽 une adresse r脙漏elle
    const resultType = result.type || '';
    const resultClass = result.class || '';
    const addressDetails = result.address || {};
    
    // V脙漏rifier que c'est bien une adresse (pas juste une ville ou un pays)
    const isValidAddress = resultType === 'house' || 
                          resultType === 'building' || 
                          resultType === 'residential' ||
                          resultClass === 'place' ||
                          (addressDetails.house_number && addressDetails.road);
    
    if (!isValidAddress && data.length > 1) {
      // Chercher un r脙漏sultat plus pr脙漏cis
      const betterResult = data.find(r => 
        r.type === 'house' || 
        r.type === 'building' || 
        (r.address && r.address.house_number)
      );
      if (betterResult) {
        Object.assign(result, betterResult);
      }
    }
    
    const lat = parseFloat(result.lat);
    const lng = parseFloat(result.lon);
    
    // V脙漏rifier que les coordonn脙漏es sont valides
    if (isNaN(lat) || isNaN(lng) || lat < -90 || lat > 90 || lng < -180 || lng > 180) {
      showNotification("芒職聽茂赂聫 Coordonn脙漏es invalides. L'adresse semble incorrecte.", "warning");
      return;
    }
    
    // V脙漏rifier que l'adresse est en Suisse (ou pays autoris脙漏)
    const country = addressDetails.country_code?.toUpperCase() || '';
    if (country && country !== 'CH' && country !== 'FR' && country !== 'DE' && country !== 'IT' && country !== 'AT') {
      showNotification(`芒職聽茂赂聫 L'adresse doit 脙陋tre en Suisse ou dans un pays voisin (actuellement: ${country}).`, "warning");
      return;
    }
    
    // D脙漏tecter le pays pour l'enregistrement (utiliser la premi脙篓re adresse)
    if (!registerData.registeredCountry && country) {
      registerData.registeredCountry = country;
    }
    
    // Stocker les informations compl脙篓tes pour v脙漏rification backend
    window.registerData.addresses[addressIndex].lat = lat;
    window.registerData.addresses[addressIndex].lng = lng;
    window.registerData.addresses[addressIndex].address = address;
    window.registerData.addresses[addressIndex].city = city;
    window.registerData.addresses[addressIndex].verified = true;
    window.registerData.addresses[addressIndex].addressDetails = {
      house_number: addressDetails.house_number || '',
      road: addressDetails.road || '',
      postcode: addressDetails.postcode || '',
      country: addressDetails.country || '',
      country_code: country
    };
    
    showNotification("芒聹聟 Adresse v脙漏rifi脙漏e et valid脙漏e !", "success");
    showRegisterStep3(); // Rafra脙庐chir pour afficher les coordonn脙漏es
  } catch (error) {
    console.error('Erreur g脙漏ocodage:', error);
    showNotification("芒聺聦 Erreur lors de la v脙漏rification. R脙漏essayez plus tard.", "error");
  }
}

async function completeRegistration() {
  // V脙漏rifier que l'email est v脙漏rifi脙漏
  if (!window.window.registerData.emailVerified) {
    showContextualError('EMAIL_NOT_VERIFIED', 'Email non v脙漏rifi脙漏');
    return;
  }
  
  // V脙漏rifier qu'au moins une adresse a des coordonn脙漏es
  const validAddresses = window.registerData.addresses.filter(addr => 
    addr.address && addr.city && addr.lat && addr.lng
  );
  
  if (validAddresses.length === 0) {
    showContextualError('VALIDATION_ERROR', 'Adresse postale requise', {
      details: 'Veuillez ajouter et g脙漏ocoder au moins une adresse postale.',
      fieldId: 'pro-postal-address'
    });
    return;
  }
  
  // V脙漏rifier le rate limiting final
  const now = Date.now();
  if (window.registerData.lastRegistrationAttempt && (now - window.registerData.lastRegistrationAttempt) < 30000) {
    const remainingSeconds = Math.ceil((30000 - (now - window.registerData.lastRegistrationAttempt)) / 1000);
    showContextualError('RATE_LIMITED', 'Trop de tentatives', { retryAfter: remainingSeconds });
    return;
  }
  
  // R脙漏cup脙漏rer l'avatar s脙漏lectionn脙漏
  const selectedAvatar = AVAILABLE_AVATARS.find(av => av.id === window.registerData.avatarId) || AVAILABLE_AVATARS[0];
  
  // Cr脙漏er l'utilisateur
  const userId = `user_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  const createdAt = new Date().toISOString();
  
  currentUser = {
    id: userId,
    name: window.registerData.username,
    firstName: window.registerData.firstName,
    lastName: window.registerData.lastName,
    email: window.registerData.email,
    avatar: selectedAvatar.emoji,
    avatarId: selectedAvatar.id,
    avatarName: selectedAvatar.name,
    avatarDescription: window.registerData.avatarDescription || '',
    bio: '',
    isLoggedIn: true,
    favorites: [],
    agenda: [],
    likes: [],
    participating: [],
    alerts: [],
    reviews: {},
    subscription: "free",
    agendaLimit: 20,
    alertLimit: 2,
    eventStatusHistory: {},
    addresses: validAddresses.map((addr, index) => ({
      address: addr.address,
      city: addr.city,
      lat: addr.lat,
      lng: addr.lng,
      isPrimary: index === 0
    })),
    registeredCountry: registerData.registeredCountry || 'CH',
    registeredCountry: registerData.registeredCountry || 'CH',
    smsNotifications: 0,
    smsLimit: 0,
    emailNotifications: 0,
    notificationPreferences: {
      email: true,
      sms: false
    },
    // Nouvelles propri脙漏t脙漏s sociales
    friends: [],
    friendRequests: [],
    sentRequests: [],
    blockedUsers: [],
    conversations: [],
    groups: [],
    lastSeen: createdAt,
    profileLinks: [],
    profilePhotos: [],
    createdAt: createdAt,
    lastLoginAt: createdAt
  };
  
  // Initialiser historique et photos si inexistants
  if (!currentUser.history) currentUser.history = [];
  if (!currentUser.photos) currentUser.photos = [];
  
  // Ajouter l'脙漏v脙漏nement de cr脙漏ation de compte 脙聽 l'historique
  currentUser.history.unshift({
    action: "Compte cr脙漏脙漏",
    icon: "冒聼聨聣",
    timestamp: createdAt
  });
  
  // Sauvegarder dans localStorage
  try {
    localStorage.setItem('currentUser', JSON.stringify(currentUser));
  } catch (e) {
    console.error('Erreur sauvegarde utilisateur:', e);
  }
  
  // INTERDICTION : Ne pas modifier le bloc compte - fonctions supprim脙漏es
  
  // Sauvegarder dans le backend (OBLIGATOIRE - v脙漏rification c脙麓t脙漏 serveur)
  try {
    const response = await fetch(`${window.API_BASE_URL}/user/register`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        email: window.registerData.email,
        username: window.registerData.username,
        password: window.registerData.password, // Le backend hash le mot de passe
        firstName: window.registerData.firstName,
        lastName: window.registerData.lastName,
        avatarId: selectedAvatar.id,
        avatarEmoji: selectedAvatar.emoji,
        avatarDescription: window.registerData.avatarDescription || '',
        addresses: currentUser.addresses.map(addr => ({
          ...addr,
          addressDetails: window.registerData.addresses.find(a => a.address === addr.address && a.city === addr.city)?.addressDetails || {}
        })),
        verificationCode: window.window.registerData.emailVerificationCode // Envoyer le code pour double v脙漏rification
      })
    });
    
    const result = await response.json();
    
    if (!response.ok) {
      // Erreur c脙麓t脙漏 backend - utiliser messages contextuels
      if (result.code === 'EMAIL_NOT_VERIFIED') {
        showContextualError('EMAIL_NOT_VERIFIED', result.error || 'Email non v脙漏rifi脙漏');
        return;
      } else if (result.code === 'EMAIL_ALREADY_EXISTS' || result.error?.includes('email') || result.error?.includes('Email')) {
        showContextualError('EMAIL_ALREADY_EXISTS', result.error || 'Email d脙漏j脙聽 utilis脙漏', { email: window.registerData.email });
        return;
      } else if (result.code === 'USERNAME_ALREADY_EXISTS' || result.error?.includes('username') || result.error?.includes('nom d\'utilisateur')) {
        showContextualError('USERNAME_ALREADY_EXISTS', result.error || 'Nom d\'utilisateur d脙漏j脙聽 pris', { username: window.registerData.username });
        return;
      } else if (result.rate_limited) {
        showContextualError('RATE_LIMITED', result.error || 'Trop de tentatives', { retryAfter: result.retry_after || 300 });
        return;
      } else if (result.error?.includes('mot de passe') || result.error?.includes('password')) {
        showContextualError('PASSWORD_TOO_WEAK', result.error || 'Mot de passe invalide', { details: result.error });
        return;
      } else {
        // Erreur g脙漏n脙漏rique avec suggestion de r脙漏essayer
        showContextualError('NETWORK_ERROR', result.error || 'Erreur lors de la cr脙漏ation du compte', {
          retryCallback: () => completeRegistration()
        });
        return;
      }
    }
    
    // Utiliser l'ID utilisateur retourn脙漏 par le backend
    if (result.userId) {
      currentUser.id = result.userId;
    }
    
    console.log('芒聹聟 Compte cr脙漏脙漏 avec succ脙篓s dans le backend:', result);
  } catch (error) {
    console.error('Erreur enregistrement backend:', error);
    showContextualError('NETWORK_ERROR', 'Erreur de connexion au serveur', {
      retryCallback: () => completeRegistration()
    });
    return; // Ne pas continuer si le backend 脙漏choue
  }
  
  showNotification("芒聹聟 Compte cr脙漏脙漏 avec succ脙篓s !", "success");
  closePublishModal();
  // INTERDICTION : Ne pas modifier le bloc compte - fonctions supprim脙漏es
  
  // Charger les donn脙漏es utilisateur
  await loadUserDataOnLogin();
}

