            <textarea id="discussion-input" placeholder="脙聣crivez un commentaire..." style="width:100%;min-height:36px;max-height:100px;padding:8px 12px;border-radius:18px;border:1px solid rgba(255,255,255,0.1);background:rgba(15,23,42,0.8);color:#e4e6eb;font-size:14px;resize:none;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;line-height:1.33;box-sizing:border-box;display:block;" onkeydown="if(event.key==='Enter' && !event.shiftKey) { event.preventDefault(); submitDiscussionComment('${type}', '${id}'); }" oninput="this.style.height='auto';this.style.height=Math.min(this.scrollHeight,100)+'px';"></textarea>
