async function processCartCheckout() {
  if (cart.length === 0) return;
  
  if (!currentUser || !currentUser.isLoggedIn) {
    openLoginModal();
    return;
  }
  
  const total = cart.reduce((sum, item) => sum + item.price, 0);
  const count = cart.length;
  
  try {
    showNotification("冒聼聮鲁 Redirection vers le paiement...", "info");
    
    // Cr脙漏er une session Stripe Checkout
    const response = await fetch(`${window.API_BASE_URL}/payments/create-checkout-session`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        userId: currentUser.id.toString(),
        paymentType: 'cart',
        items: cart.map(item => ({
          type: item.type,
          id: item.id,
          price: item.price
        })),
        amount: total,
        currency: 'CHF',
        email: currentUser.email
      })
    });
    
    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.error || 'Erreur lors de la cr脙漏ation de la session');
    }
    
    const { sessionId, publicKey } = await response.json();
    
    // Initialiser Stripe si pas encore fait
    if (!stripe && publicKey) {
      initStripe(publicKey);
    }
    
    if (!stripe) {
      throw new Error('Stripe non disponible');
    }
    
    // Rediriger vers Stripe Checkout
    const result = await stripe.redirectToCheckout({ sessionId });
    
    if (result.error) {
      showNotification(`芒聺聦 Erreur : ${result.error.message}`, "error");
    }
  } catch (error) {
    console.error('Erreur checkout:', error);
    showNotification(`芒聺聦 Erreur lors du paiement : ${error.message}`, "error");
  }
}

// Fonction de compatibilit脙漏 (fallback si Stripe 脙漏choue)
function checkoutCart() {
  processCartCheckout().catch(() => {
    // Fallback : simulation locale si l'API 脙漏choue
    const total = cart.reduce((sum, item) => sum + item.price, 0);
    const count = cart.length;
    cart.forEach(item => {
      if (!paidContacts.includes(item.key)) {
        paidContacts.push(item.key);
      }
      if (!currentUser.agenda.includes(item.key)) {
        currentUser.agenda.push(item.key);
      }
    });
    playPaymentSound();
    cart = [];
    updateCartCount();
    showNotification(`芒聹聟 Paiement simul脙漏 (mode d脙漏mo) : ${total.toFixed(2)} CHF`, "info");
    closePublishModal();
    refreshMarkers();
  });
}

async function processContactPayment(type, id) {
  if (!currentUser || !currentUser.isLoggedIn) {
    openLoginModal();
    return;
  }
  
  try {
    showNotification("冒聼聮鲁 Redirection vers le paiement...", "info");
    
    // Cr脙漏er une session Stripe Checkout
    const response = await fetch(`${window.API_BASE_URL}/payments/create-checkout-session`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        userId: currentUser.id.toString(),
        paymentType: 'contact',
        itemType: type,
        itemId: id,
        amount: 1.00, // CHF 1.芒聙聯
        currency: 'CHF',
        email: currentUser.email
      })
    });
    
    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.error || 'Erreur lors de la cr脙漏ation de la session');
    }
    
    const { sessionId, publicKey } = await response.json();
    
    // Initialiser Stripe si pas encore fait
    if (!stripe && publicKey) {
      initStripe(publicKey);
    }
    
    if (!stripe) {
      throw new Error('Stripe non disponible');
    }
    
    // Rediriger vers Stripe Checkout
    const result = await stripe.redirectToCheckout({ sessionId });
    
    if (result.error) {
      showNotification(`芒聺聦 Erreur : ${result.error.message}`, "error");
    }
  } catch (error) {
    console.error('Erreur paiement:', error);
    showNotification(`芒聺聦 Erreur lors du paiement : ${error.message}`, "error");
  }
}

// Fonction de compatibilit脙漏 (fallback si Stripe 脙漏choue)
function simulatePayment(type, id) {
  processContactPayment(type, id).catch(() => {
    // Fallback : simulation locale si l'API 脙漏choue
    const key = `${type}:${id}`;
    if (!paidContacts.includes(key)) {
      paidContacts.push(key);
    }
    if (!currentUser.agenda.includes(key)) {
      currentUser.agenda.push(key);
    }
    playPaymentSound();
    showNotification("芒聹聟 Paiement simul脙漏 (mode d脙漏mo)", "info");
    closePublishModal();
    refreshMarkers();
  });
}

