// Fonction pour confirmer et ex脙漏cuter la suppression du compte
async function confirmDeleteAccount() {
  if (!currentUser || !currentUser.isLoggedIn) {
    showNotification('芒聺聦 Vous devez 脙陋tre connect脙漏 pour supprimer votre compte', 'error');
    return;
  }
  
  // Demander une confirmation finale
  const finalConfirm = confirm('芒職聽茂赂聫 DERNI脙聢RE CONFIRMATION\n\nCette action supprimera d脙漏finitivement votre compte et toutes vos donn脙漏es.\n\nCette action est IRR脙聣VERSIBLE.\n\nVoulez-vous vraiment continuer ?');
  
  if (!finalConfirm) {
    return;
  }
  
  try {
    showNotification('冒聼聴聭茂赂聫 Suppression du compte en cours...', 'info');
    
    const token = localStorage.getItem('accessToken') || sessionStorage.getItem('accessToken');
    if (!token) {
      showNotification('芒聺聦 Token d\'authentification manquant', 'error');
      return;
    }
    
    const response = await fetch(`${window.API_BASE_URL}/user/account`, {
      method: 'DELETE',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
      body: JSON.stringify({
        confirm: true
      })
    });
    
    const result = await response.json();
    
    if (!response.ok) {
      if (result.code === 'CONFIRMATION_REQUIRED') {
        showNotification('芒聺聦 Confirmation requise pour supprimer le compte', 'error');
      } else {
        showNotification(`芒聺聦 Erreur: ${result.error || 'Impossible de supprimer le compte'}`, 'error');
      }
      return;
    }
    
    // Suppression r脙漏ussie - tout supprimer (compte n'existe plus)
    showNotification('芒聹聟 Compte supprim脙漏 avec succ脙篓s', 'success');
    
    localStorage.removeItem('currentUser');
    sessionStorage.removeItem('currentUser');
    localStorage.removeItem('accessToken');
    localStorage.removeItem('refreshToken');
    localStorage.removeItem('rememberMe');
    sessionStorage.removeItem('accessToken');
    sessionStorage.removeItem('refreshToken');
    sessionStorage.removeItem('rememberMe');
    
    currentUser = getDefaultUser();
    currentUser = null;
    
    // Fermer le modal
    closePublishModal();
    
    // Recharger la page apr脙篓s 2 secondes
    setTimeout(() => {
      window.location.reload();
    }, 2000);
    
  } catch (error) {
    console.error('Erreur suppression compte:', error);
    showNotification('芒聺聦 Erreur lors de la suppression du compte. Veuillez r脙漏essayer.', 'error');
  }
}

// Fonction pour ouvrir une fen脙陋tre externe pour chaque bloc
function openAccountWindow(blockType) {
  console.log('[ACCOUNT WINDOW] Ouverture fen脙陋tre pour:', blockType);
  
  // 芒職聽茂赂聫芒職聽茂赂聫芒職聽茂赂聫 CRITIQUE : Ne pas fermer le modal si c'est pour modifier-profil
  // Car openEditProfileModal a besoin que le modal soit ouvert
  if (blockType !== 'modifier-profil') {
    closePublishModal();
  }
  
  // Cr脙漏er une nouvelle fen脙陋tre avec le contenu du bloc
  const windowFeatures = 'width=600,height=700,scrollbars=yes,resizable=yes';
  const windowName = `account_${blockType}_${Date.now()}`;
  
  // Cr脙漏er le HTML pour la fen脙陋tre
  let windowContent = '';
  
  if (blockType === 'agenda') {
    const agendaItems = (currentUser.agenda || []).map(key => {
      const [type, id] = key.split(":");
      const data = type === "event" ? eventsData : type === "booking" ? bookingsData : servicesData;
      return data.find(i => i.id === parseInt(id));
    }).filter(Boolean);
    
    windowContent = `
      <!DOCTYPE html>
      <html>
      <head>
        <title>Mon Agenda - MapEvent</title>
        <style>
          body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; background: #0f172a; color: #fff; margin: 0; padding: 20px; }
          h1 { margin: 0 0 20px; font-size: 24px; }
        </style>
      </head>
      <body>
        <h1>冒聼聯聟 Mon Agenda</h1>
        ${agendaItems.length === 0 ? '<p>Votre agenda est vide</p>' : agendaItems.map(item => `<div style="padding:12px;margin-bottom:8px;background:rgba(15,23,42,0.5);border-radius:8px;">${escapeHtml(item.title || item.name || 'Sans titre')}</div>`).join('')}
      </body>
      </html>
    `;
  } else if (blockType === 'notifications') {
    openProximityAlertsView();
    return;
  } else if (blockType === 'modifier-profil') {
    // 芒職聽茂赂聫芒職聽茂赂聫芒職聽茂赂聫 CRITIQUE : Pour modifier-profil, afficher le formulaire dans le modal au lieu d'une nouvelle fen脙陋tre
    console.log('[ACCOUNT WINDOW] modifier-profil d脙漏tect脙漏 - Affichage dans modal au lieu de nouvelle fen脙陋tre');
    
    // Essayer d'abord showAccountBlockContent (affiche dans le modal)
    if (typeof showAccountBlockContent === 'function') {
      console.log('[ACCOUNT WINDOW] Utilisation showAccountBlockContent pour modifier-profil');
      showAccountBlockContent('modifier-profil');
      return; // Ne pas ouvrir de nouvelle fen脙陋tre
    }
    
    // Fallback : ouvrir le formulaire d'脙漏dition complet
    if (typeof window.openEditProfileModal === 'function') {
      console.log('[ACCOUNT WINDOW] Utilisation window.openEditProfileModal (fallback)');
      window.openEditProfileModal();
      return;
    } else if (typeof openEditProfileModal === 'function') {
      console.log('[ACCOUNT WINDOW] Utilisation openEditProfileModal (fallback)');
      openEditProfileModal();
      return;
    } else {
      console.error('[ACCOUNT WINDOW] 芒聺聦 Aucune fonction disponible pour modifier-profil');
      showNotification('芒職聽茂赂聫 Fonctionnalit脙漏 en cours de d脙漏veloppement', 'info');
      return;
    }
  } else if (blockType === 'mes-annonces') {
    // 芒聹聟 MES ANNONCES - Afficher dans un modal
    console.log('[ACCOUNT WINDOW] mes-annonces d脙漏tect脙漏 - Ouverture du modal Mes annonces');
    showMesAnnoncesModal();
    return;
  } else {
    // Pour les autres blocs, utiliser showAccountBlockContent dans une nouvelle fen脙陋tre
    windowContent = `
      <!DOCTYPE html>
      <html>
      <head>
        <title>${blockType} - MapEvent</title>
        <style>
          body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; background: #0f172a; color: #fff; margin: 0; padding: 20px; }
        </style>
      </head>
      <body>
        <p>Fonctionnalit脙漏 脙聽 venir</p>
      </body>
      </html>
    `;
  }
  
  try {
    const newWindow = window.open('', windowName, windowFeatures);
    if (newWindow) {
      newWindow.document.write(windowContent);
      newWindow.document.close();
      console.log('[ACCOUNT WINDOW] Fen脙陋tre ouverte avec succ脙篓s:', windowName);
    } else {
      console.error('[ACCOUNT WINDOW] 脙聣chec ouverture fen脙陋tre - popup bloqu脙漏e?');
      alert('Veuillez autoriser les popups pour cette fonctionnalit脙漏');
    }
  } catch (e) {
    console.error('[ACCOUNT WINDOW] Erreur ouverture fen脙陋tre:', e);
    alert('Erreur lors de l\'ouverture de la fen脙陋tre: ' + e.message);
  }
}

// Fonction pour demander "rester connect脙漏" avant d脙漏connexion
