// ============================================
// UTILITAIRES
// ============================================
function formatEventDateRange(startIso, endIso, isScraped = false) {
  // Date obligatoire - r脙漏f脙漏rence: js/core/utils.js
  if (!startIso || !endIso) return "";
  const s = new Date(startIso);
  const e = new Date(endIso);

  const optD = { day: "2-digit", month: "2-digit" };
  const optT = { hour: "2-digit", minute: "2-digit" };

  const sd = s.toLocaleDateString("fr-CH", optD);
  const ed = e.toLocaleDateString("fr-CH", optD);
  
  // Pour les 脙漏v脙漏nements scrap脙漏s, on affiche --:-- 脙聽 la place de l'heure
  if (isScraped) {
    if (sd === ed) return `${sd} --:-- 芒聙聯 --:--`;
    return `${sd} --:-- 芒聙聯 ${ed} --:--`;
  }
  
  const st = s.toLocaleTimeString("fr-CH", optT);
  const et = e.toLocaleTimeString("fr-CH", optT);

  if (sd === ed) return `${sd} ${st}芒聙聯${et}`;
  return `${sd} ${st} 芒聙聯 ${ed} ${et}`;
}

function escapeHtml(str) {
  if (!str) return "";
  return String(str)
    .replace(/&/g, "&amp;")
    .replace(/"/g, "&quot;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

// Retirer tous les num脙漏ros de t脙漏l脙漏phone des descriptions (bookings, services)
function stripPhoneNumbers(text) {
  if (!text) return "";
  return String(text)
    .replace(/冒聼聯聻\s*[^\n|]*/g, '')
    .replace(/芒聵聨\s*[^\n|]*/g, '')
    .replace(/冒聼聯卤\s*[^\n|]*[\d\s\.\-\(\)]{7,}[^\n|]*/g, '')
    .replace(/(?:Tel|T脙漏l|T脙漏l脙漏phone|Phone|Tel\.|T脙漏l\.)\s*[:.]?\s*[\+]?[\d\s\.\-\(\)]{7,}/gi, '')
    .replace(/(?:Mobile|Portable|Cell)\s*[:.]?\s*[\+]?[\d\s\.\-\(\)]{7,}/gi, '')
    .replace(/(?:\+\d{1,3}[\s\.\-]?)?\(?\d{2,4}\)?[\s\.\-]?\d{2,4}[\s\.\-]?\d{2,4}[\s\.\-]?\d{0,4}/g, (m) => {
      const d = m.replace(/\D/g, '');
      return d.length >= 8 ? '' : m;
    })
    .replace(/\d{2}[\s\.\-]?\d{2}[\s\.\-]?\d{2}[\s\.\-]?\d{2}[\s\.\-]?\d{2}/g, '')
    .replace(/\b0\d[\s\.\-]?\d{2}[\s\.\-]?\d{2}[\s\.\-]?\d{2}[\s\.\-]?\d{2}\b/g, '')
    .replace(/\s{2,}/g, ' ')
    .trim();
}

// ============================================
// DRAG & DROP PANNEAU FILTRE
// ============================================
function initDragDropPanel() {
  const panel = document.getElementById("left-panel");
  if (!panel) return;
  
  let isDragging = false;
  let startX, startY, startLeft, startTop;
  
  panel.addEventListener("mousedown", (e) => {
    // Ne drag que si on clique sur l'en-t脙陋te
    if (e.target.closest("#explorer-columns") || e.target.closest("input") || e.target.closest("button")) {
      return;
    }
    
    isDragging = true;
    panel.classList.add("dragging");
    
    startX = e.clientX;
    startY = e.clientY;
    startLeft = panel.offsetLeft;
    startTop = panel.offsetTop;
    
    e.preventDefault();
  });
  
  document.addEventListener("mousemove", (e) => {
    if (!isDragging) return;
    
    const dx = e.clientX - startX;
    const dy = e.clientY - startY;
    
    panel.style.left = (startLeft + dx) + "px";
    panel.style.top = (startTop + dy) + "px";
  });
  
  document.addEventListener("mouseup", () => {
    isDragging = false;
    panel.classList.remove("dragging");
  });
}

// Initialiser apr脙篓s le chargement
document.addEventListener("DOMContentLoaded", () => {
  setTimeout(initDragDropPanel, 500);
});

