function makeDonation(amount) {
  if (amount === 0) {
    const customAmount = prompt("Montant de votre don (CHF) :");
    if (customAmount && !isNaN(customAmount) && parseFloat(customAmount) > 0) {
      amount = parseFloat(customAmount);
    } else {
      return;
    }
  }
  
  showNotification(`冒聼聦聧 Merci pour votre don de ${amount} CHF ! La Terre vous remercie 冒聼聮職`, "success");
  closePublishModal();
  
  // Afficher un message de remerciement apr脙篓s
  setTimeout(() => {
    showNotification("冒聼聦鲁 Votre contribution sera utilis脙漏e pour prot脙漏ger notre plan脙篓te.", "info");
  }, 2000);
}

// ============================================
// SYST脙聢ME D'ALERTES ET D'ALARMES - LEADER MONDIAL
// ============================================

// API_BASE_URL est maintenant d脙漏fini en haut du fichier

// Fonction pour charger l'utilisateur depuis /api/user/me (source de v脙漏rit脙漏)
async function loadCurrentUserFromAPI() {
  try {
    // LOG: API_BASE_URL utilis脙漏
    console.log('[AUTH] API_BASE_URL:', window.API_BASE_URL);
    
    const accessToken = getAuthToken();
    const refreshToken = getRefreshToken();
    
    if (!accessToken) {
      console.log('[AUTH] Pas de token');
      localStorage.removeItem('currentUser');
      sessionStorage.removeItem('currentUser');
      currentUser = getDefaultUser();
      return null;
    }
    
    // LOG: Tentative /api/user/me
    console.log('[AUTH] Appel GET /api/user/me...');
    
    // Appeler /api/user/me avec le token
    const response = await fetch(`${window.API_BASE_URL}/user/me`, {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${accessToken}`
      }
    });
    
    // LOG: Status /api/user/me
    console.log('[AUTH] GET /api/user/me - Status:', response.status, response.statusText);
    
    if (response.ok) {
      const data = await response.json();
      const user = data.user;
      
      // IMPORTANT: Normaliser la source d'avatar avec priorit脙漏 claire
      // Priorit脙漏: profile_photo_url > profilePhoto > avatarUrl > avatar > emoji
      const avatarUrl = user.profile_photo_url || user.profilePhoto || user.avatarUrl || user.avatar || null;
      
      // Mettre 脙聽 jour currentUser avec les donn脙漏es du serveur (source de v脙漏rit脙漏)
      // Exclure agenda du spread car il sera charg脙漏 s脙漏par脙漏ment par loadAgendaFromBackend()
      const { agenda: _apiAgenda, ...userWithoutAgenda } = user;
      const existingAgenda = currentUser?.agenda || [];
      
      currentUser = {
        ...userWithoutAgenda,
        isLoggedIn: true,
        accessToken: accessToken,
        refreshToken: refreshToken,
        // Normaliser avatar avec priorit脙漏
        avatarUrl: avatarUrl, // Champ unifi脙漏
        profilePhoto: avatarUrl, // Alias
        profile_photo_url: avatarUrl, // Alias
        avatar: avatarUrl || '冒聼聭陇', // Fallback emoji
        // Pr脙漏server l'agenda existant en attendant le chargement complet par loadAgendaFromBackend()
        agenda: (_apiAgenda && Array.isArray(_apiAgenda) && _apiAgenda.length > 0) ? _apiAgenda : existingAgenda
      };
      
      window.currentUser = currentUser;
      
      console.log('[AUTH] Utilisateur charge depuis /api/user/me:', user.email);
      console.log('[AVATAR] Avatar normalise:', avatarUrl ? avatarUrl.substring(0, 50) + '...' : 'null (emoji)');
      
      // Mettre 脙聽 jour l'UI imm脙漏diatement apr脙篓s chargement
      if (typeof updateAccountBlockLegitimately === 'function') {
        setTimeout(() => updateAccountBlockLegitimately(), 100);
      }
      
      return currentUser;
    } else if (response.status === 401) {
      // Token expir脙漏, tenter refresh
      console.log('[AUTH] Token expire (401), tentative refresh...');
      
      if (!refreshToken) {
        console.log('[AUTH] Pas de refresh token');
        localStorage.removeItem('currentUser');
        sessionStorage.removeItem('currentUser');
        currentUser = getDefaultUser();
        return null;
      }
      
      // LOG: Tentative /api/auth/refresh
      console.log('[AUTH] Appel POST /api/auth/refresh...');
      
      // Appeler /api/auth/refresh
      const refreshResponse = await fetch(`${window.API_BASE_URL}/auth/refresh`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ refreshToken: refreshToken })
      });
      
      // LOG: Status refresh
      console.log('[AUTH] POST /api/auth/refresh - Status:', refreshResponse.status, refreshResponse.statusText);
      
      if (refreshResponse.ok) {
        const refreshData = await refreshResponse.json();
        const newAccessToken = refreshData.accessToken;
        
        // Sauvegarder le nouveau token
        localStorage.setItem('accessToken', newAccessToken);
        console.log('[AUTH] Nouveau accessToken obtenu');
        
        // R脙漏essayer /api/user/me avec le nouveau token
        console.log('[AUTH] Retry GET /api/user/me avec nouveau token...');
        const retryResponse = await fetch(`${window.API_BASE_URL}/user/me`, {
          method: 'GET',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${newAccessToken}`
          }
        });
        
        // LOG: Status retry /api/user/me
        console.log('[AUTH] Retry GET /api/user/me - Status:', retryResponse.status, retryResponse.statusText);
        
        if (retryResponse.ok) {
          const retryData = await retryResponse.json();
          const user = retryData.user;
          
          // IMPORTANT: Normaliser avatar avec priorit脙漏 claire
          const avatarUrl = user.profile_photo_url || user.profilePhoto || user.avatarUrl || user.avatar || null;
          
          // Exclure agenda du spread car charg脙漏 s脙漏par脙漏ment par loadAgendaFromBackend()
          const { agenda: _retryAgenda, ...retryUserWithoutAgenda } = user;
          const retryExistingAgenda = currentUser?.agenda || [];
          
          currentUser = {
            ...retryUserWithoutAgenda,
            isLoggedIn: true,
            accessToken: newAccessToken,
            refreshToken: refreshToken,
            avatarUrl: avatarUrl, // Champ unifi脙漏
            profilePhoto: avatarUrl, // Alias
            profile_photo_url: avatarUrl, // Alias
            avatar: avatarUrl || '冒聼聭陇', // Fallback emoji
            agenda: (_retryAgenda && Array.isArray(_retryAgenda) && _retryAgenda.length > 0) ? _retryAgenda : retryExistingAgenda
          };
          
          window.currentUser = currentUser;
          console.log('[AUTH] Utilisateur charge apres refresh:', user.email);
          console.log('[AVATAR] Avatar normalise apres refresh:', avatarUrl ? avatarUrl.substring(0, 50) + '...' : 'null (emoji)');
          
          // Mettre 脙聽 jour l'UI imm脙漏diatement apr脙篓s refresh
          if (typeof updateAccountBlockLegitimately === 'function') {
            setTimeout(() => updateAccountBlockLegitimately(), 100);
          }
          
          return currentUser;
        } else {
          console.log('[AUTH] Retry /api/user/me echoue:', retryResponse.status);
        }
      } else {
        console.log('[AUTH] Refresh echoue:', refreshResponse.status);
      }
      
      // Refresh 脙漏chou脙漏 - tokens conserv脙漏s
      console.log('[AUTH] Refresh echoue');
      localStorage.removeItem('currentUser');
      sessionStorage.removeItem('currentUser');
      currentUser = getDefaultUser();
      return null;
    } else {
      // Autre erreur
      console.error('[AUTH] Erreur chargement utilisateur:', response.status);
      return null;
    }
  } catch (error) {
    console.error('[AUTH] Erreur lors du chargement utilisateur:', error);
    return null;
  }
}

// --- CONFIGURATION STRIPE ---
// Note: La cl脙漏 publique sera r脙漏cup脙漏r脙漏e depuis le backend lors de la cr脙漏ation de la session
let stripe = null;
let stripePublicKey = null;

// Initialiser Stripe (sera fait apr脙篓s r脙漏cup脙漏ration de la cl脙漏 publique)
function initStripe(publicKey) {
  if (!publicKey) {
    console.warn('芒職聽茂赂聫 Cl脙漏 publique Stripe manquante');
    return;
  }
  
  // Charger Stripe.js 脙聽 la demande si pas encore charg脙漏
  if (typeof Stripe === 'undefined') {
    console.log('芒聫鲁 Chargement de Stripe.js 脙聽 la demande...');
    if (typeof window.loadStripe === 'function') {
      window.loadStripe().then(() => {
      if (typeof Stripe !== 'undefined') {
          try {
        stripe = Stripe(publicKey);
        stripePublicKey = publicKey;
            console.log('芒聹聟 Stripe initialis脙漏 (charg脙漏 脙聽 la demande)');
          } catch (error) {
            console.error('芒聺聦 Erreur initialisation Stripe:', error);
          }
      } else {
          console.error('芒聺聦 Stripe.js toujours non disponible apr脙篓s chargement');
      }
      });
    } else {
      console.error('芒聺聦 loadStripe non disponible');
    }
    return;
  }
  
  try {
    stripe = Stripe(publicKey);
    stripePublicKey = publicKey;
    console.log('芒聹聟 Stripe initialis脙漏 avec succ脙篓s');
  } catch (error) {
    console.error('芒聺聦 Erreur initialisation Stripe:', error);
  }
}

// Stripe.js est charg脙漏 脙聽 la demande (lazy-load) - pas de v脙漏rification au d脙漏marrage

// 脙聣tat des alertes
let alertsViewOpen = false;
let alertsScrollPosition = 0;
let selectedAlertId = null;
let alarmsViewOpen = false;

// Variables pour les alarmes
let currentUserAlarms = []; // [{alertId, eventId, favoriteId, favoriteName, favoriteMode, timeBefore: {value, unit}, createdAt}]
let alarmsForAgenda = []; // M脙陋me structure pour l'agenda

// ============================================
// D脙聣TECTION AUTOMATIQUE DES FAVORIS DANS LES 脙聣V脙聣NEMENTS
// ============================================

// V脙漏rifier si des favoris apparaissent dans de nouveaux 脙漏v脙漏nements
async function checkFavoritesInNewEvents(newEvents) {
  if (!currentUser.isLoggedIn || !currentUser.favorites || currentUser.favorites.length === 0) {
    return;
  }

  const maxAlerts = getAlertLimit();
  if (maxAlerts === 0) return; // Pas d'alertes pour les utilisateurs gratuits

  const newAlerts = [];

  // Pour chaque nouvel 脙漏v脙漏nement
  newEvents.forEach(event => {
    if (!event || !event.title) return;

    const eventTitle = (event.title || '').toLowerCase();
    const eventDescription = (event.description || '').toLowerCase();
    const eventLocation = (event.location || event.city || '').toLowerCase();

    // Pour chaque favori de l'utilisateur
    currentUser.favorites.forEach(favorite => {
      if (!favorite || !favorite.name) return;

      const favoriteName = favorite.name.toLowerCase();
      
      // V脙漏rifier si le nom du favori appara脙庐t dans le titre, description ou location
      const foundInTitle = eventTitle.includes(favoriteName);
      const foundInDescription = eventDescription.includes(favoriteName);
      const foundInLocation = eventLocation.includes(favoriteName);

      if (foundInTitle || foundInDescription || foundInLocation) {
        // V脙漏rifier si l'alerte existe d脙漏j脙聽
        const alertExists = currentUser.alerts.some(a => 
          a.eventId === event.id.toString() && 
          a.favoriteId === favorite.id &&
          a.status !== 'deleted'
        );

        if (!alertExists) {
          // 芒聹聟 NOUVEAU : V脙漏rifier la distance entre l'utilisateur et l'脙漏v脙漏nement
          // L'alerte n'est cr脙漏脙漏e que si l'脙漏v脙漏nement est 脙聽 moins de 75 km d'au moins une adresse de l'utilisateur
          if (!event.lat || !event.lng) {
            // Si l'脙漏v脙漏nement n'a pas de coordonn脙漏es, on ne peut pas calculer la distance
            // On ne cr脙漏e pas l'alerte
            return;
          }

          // V脙漏rifier si l'utilisateur a au moins une adresse d脙漏finie
          if (!currentUser.addresses || currentUser.addresses.length === 0) {
            // Si l'utilisateur n'a pas d'adresse, on ne cr脙漏e pas l'alerte
            console.log('芒職聽茂赂聫 Aucune adresse utilisateur d脙漏finie - alerte non cr脙漏脙漏e');
            return;
          }

          // V脙漏rifier la distance pour chaque adresse de l'utilisateur
          let distanceToUser = null;
          let closestAddress = null;
          
          for (const address of currentUser.addresses) {
            if (address.lat && address.lng) {
              const distance = calculateDistance(
                address.lat, address.lng,
                event.lat, event.lng
              );
              
              // Si l'脙漏v脙漏nement est 脙聽 moins de 75 km de cette adresse
              if (distance <= 75) {
                if (!distanceToUser || distance < distanceToUser) {
                  distanceToUser = distance;
                  closestAddress = address;
                }
              }
            }
          }

          // 芒聹聟 Condition : L'alerte n'est cr脙漏脙漏e que si l'脙漏v脙漏nement est 脙聽 moins de 75 km d'au moins une adresse
          if (distanceToUser === null || distanceToUser > 75) {
            console.log(`芒職聽茂赂聫 脙聣v脙漏nement trop loin (${distanceToUser ? distanceToUser + ' km' : 'distance inconnue'} > 75 km) - alerte non cr脙漏脙漏e`);
            return;
          }

          // Calculer la distance entre le favori et l'脙漏v脙漏nement (pour affichage)
          let distanceToFavorite = null;
          if (favorite.lat && favorite.lng) {
            distanceToFavorite = calculateDistance(
              event.lat, event.lng,
              favorite.lat, favorite.lng
            );
          }

          // V脙漏rifier la limite d'alertes pour d脙漏terminer si elle doit 脙陋tre flout脙漏e
          const alertLimit = getAlertLimit();
          const activeAlerts = currentUser.alerts.filter(a => a.status !== 'deleted' && !a.isBlurred);
          const isBlurred = alertLimit !== Infinity && activeAlerts.length >= alertLimit;

          const alert = {
            id: `alert-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
            eventId: event.id.toString(),
            favoriteId: favorite.id,
            favoriteName: favorite.name,
            favoriteMode: favorite.mode || favorite.type || 'event',
            distance: distanceToFavorite, // Distance entre favori et 脙漏v脙漏nement
            distanceToUser: distanceToUser, // Distance entre utilisateur et 脙漏v脙漏nement
            closestAddress: closestAddress ? (closestAddress.address || closestAddress.city) : null,
            status: 'new',
            isBlurred: isBlurred, // 芒聹聟 Alerte flout脙漏e si limite atteinte
            creationDate: new Date().toISOString(),
            eventTitle: event.title,
            eventDate: event.startDate || event.date
          };

          newAlerts.push(alert);
          
          // Si l'alerte est flout脙漏e, supprimer les alarmes correspondantes (elles n'existent pas encore, mais on pr脙漏pare)
          // Les alarmes seront supprim脙漏es automatiquement quand elles seront cr脙漏脙漏es pour une alerte flout脙漏e
        }
      }
    });
  });

  // Ajouter les nouvelles alertes
  if (newAlerts.length > 0) {
    // Sauvegarder dans le backend
    for (const alert of newAlerts) {
      try {
        const response = await fetch(`${window.API_BASE_URL}/user/alerts`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            userId: currentUser.id.toString(),
            alert: alert
          })
        });

        if (response.ok) {
          currentUser.alerts.push(alert);
        }
      } catch (error) {
        console.error('Erreur cr脙漏ation alerte:', error);
      }
    }

    // Afficher la fen脙陋tre popup au login si l'utilisateur vient de se connecter
    if (currentUser && currentUser.isLoggedIn) {
      showAlertsLoginPopup(newAlerts);
    }
  }
}

// Calculer la distance entre deux points (formule de Haversine)
// Fonction calculateDistance d脙漏j脙聽 d脙漏finie plus haut (ligne 2753)
// Cette fonction utilise la signature: calculateDistance(lat1, lng1, lat2, lng2)

// ============================================
// FEN脙聤TRE POPUP D'ALERTES AU LOGIN
